--
-- Name: accept_account_invite(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.accept_account_invite(invite_token text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_email text := lower(coalesce(auth.jwt()->>'email', ''));
  v_inv public.account_invitations%rowtype;
  v_role text;
  v_has_admin boolean := false;
  v_member_role public.account_members.role%type;
  v_previous_role text;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select *
  into v_inv
  from public.account_invitations
  where token = invite_token
  limit 1;

  if v_inv.id is null then
    raise exception 'Invitation not found';
  end if;

  if v_email = '' or lower(v_inv.email) <> v_email then
    raise exception 'Invitation email mismatch';
  end if;

  if v_inv.revoked_at is not null then
    raise exception 'Invitation revoked';
  end if;

  if v_inv.accepted_at is not null then
    return jsonb_build_object('ok', true, 'already_accepted', true, 'account_id', v_inv.account_id);
  end if;

  v_role := lower(coalesce(v_inv.role::text, 'staff'));
  select exists (
    select 1
    from pg_type t
    join pg_namespace n on n.oid = t.typnamespace
    join pg_enum e on e.enumtypid = t.oid
    where n.nspname = 'public'
      and t.typname = 'account_role'
      and e.enumlabel = 'admin'
  )
  into v_has_admin;
  if v_role = 'admin' and not v_has_admin then
    v_role := 'staff';
  end if;
  if v_role not in ('owner', 'admin', 'staff', 'tenant', 'contractor') then
    v_role := 'staff';
  end if;
  v_member_role := v_role;

  select lower(am.role::text)
  into v_previous_role
  from public.account_members am
  where am.account_id = v_inv.account_id
    and am.user_id = v_uid
  limit 1;

  insert into public.account_members(account_id, user_id, role)
  values (v_inv.account_id, v_uid, v_member_role)
  on conflict (account_id, user_id) do update set role = excluded.role;

  update public.account_invitations
  set accepted_at = now(),
      accepted_by = v_uid
  where id = v_inv.id;

  perform public.log_security_event(
    v_inv.account_id,
    'invite_accepted',
    'account_invitation',
    v_inv.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'invite_id', v_inv.id,
        'accepted_user_id', v_uid,
        'invited_role', v_role,
        'email', lower(v_inv.email),
        'account_id', v_inv.account_id
      )
    )
  );

  if v_previous_role is not null and v_previous_role is distinct from v_role then
    perform public.log_security_event(
      v_inv.account_id,
      'role_changed',
      'account_member',
      v_uid,
      jsonb_strip_nulls(
        jsonb_build_object(
          'target_user_id', v_uid,
          'old_role', v_previous_role,
          'new_role', v_role,
          'change_source', 'invite_acceptance',
          'invite_id', v_inv.id
        )
      )
    );
  end if;

  return jsonb_build_object('ok', true, 'account_id', v_inv.account_id, 'role', v_role);
end;
$$;


ALTER FUNCTION public.accept_account_invite(invite_token text) OWNER TO postgres;

