--
-- Name: activate_lease(uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.activate_lease(p_lease_id uuid, p_require_signatures boolean DEFAULT false) RETURNS public.leases
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_lease public.leases;
  v_account_id uuid;
  v_property_id uuid;
  v_missing integer;
begin
  if p_lease_id is null then
    raise exception 'lease_id is required';
  end if;

  select * into v_lease
  from public.leases
  where id = p_lease_id;

  if not found then
    raise exception 'Lease not found';
  end if;

  v_account_id := v_lease.account_id;
  v_property_id := v_lease.property_id;

  if public.account_role_for(v_account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_lease.status <> 'draft' then
    raise exception 'Only draft leases can be activated';
  end if;

  if exists (
    select 1 from public.leases
    where property_id = v_property_id
      and status = 'active'
      and id <> p_lease_id
  ) then
    raise exception 'An active lease already exists for this property';
  end if;

  if p_require_signatures then
    -- Require that every signature request for lease documents is signed
    select count(*) into v_missing
    from public.lease_signatures s
    join public.lease_documents d on d.id = s.lease_document_id
    where d.lease_id = p_lease_id
      and d.requires_signature = true
      and s.status <> 'signed';

    if coalesce(v_missing,0) > 0 then
      raise exception 'Missing signatures: %', v_missing;
    end if;
  end if;

  update public.leases
  set status = 'active',
      updated_at = now()
  where id = p_lease_id
  returning * into v_lease;

  return v_lease;
end;
$$;


ALTER FUNCTION public.activate_lease(p_lease_id uuid, p_require_signatures boolean) OWNER TO postgres;

--
-- Name: activate_lease_and_approve_application(uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.activate_lease_and_approve_application(p_lease_id uuid, p_require_signatures boolean DEFAULT true) RETURNS public.leases
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_lease public.leases;
  v_missing integer;
begin
  if p_lease_id is null then
    raise exception 'lease_id is required';
  end if;

  select * into v_lease
  from public.leases
  where id = p_lease_id;

  if not found then
    raise exception 'Lease not found';
  end if;

  if public.account_role_for(v_lease.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_lease.status <> 'draft' then
    raise exception 'Only draft leases can be activated';
  end if;

  if exists (
    select 1 from public.leases
    where property_id = v_lease.property_id
      and status = 'active'
      and id <> p_lease_id
  ) then
    raise exception 'An active lease already exists for this property';
  end if;

  if p_require_signatures then
    -- Requires: lease_documents + lease_signatures exist (from earlier scripts)
    select count(*) into v_missing
    from public.lease_signatures s
    join public.lease_documents d on d.id = s.lease_document_id
    where d.lease_id = p_lease_id
      and d.requires_signature = true
      and s.status <> 'signed';

    if coalesce(v_missing,0) > 0 then
      raise exception 'Missing signatures: %', v_missing;
    end if;
  end if;

  update public.leases
  set status = 'active',
      updated_at = now()
  where id = p_lease_id
  returning * into v_lease;

  -- Now mark the application as fully approved (only at activation time)
  if v_lease.application_id is not null then
    update public.rental_applications
    set status = 'approved',
        updated_at = now()
    where id = v_lease.application_id
      and status = 'accepted_pending_signing';
  end if;

  return v_lease;
end;
$$;


ALTER FUNCTION public.activate_lease_and_approve_application(p_lease_id uuid, p_require_signatures boolean) OWNER TO postgres;

