--

CREATE FUNCTION public.activity_log_write(p_account_id uuid, p_entity_type text, p_entity_id uuid, p_action text, p_field text DEFAULT NULL::text, p_old_value text DEFAULT NULL::text, p_new_value text DEFAULT NULL::text, p_meta jsonb DEFAULT NULL::jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'auth'
    AS $$
begin
  insert into public.activity_log (
    account_id,
    entity_type,
    entity_id,
    action,
    field,
    old_value,
    new_value,
    meta,
    actor_user_id,
