  values (
    p_account_id,
    p_entity_type,
    p_entity_id,
    p_action,
    p_field,
    p_old_value,
    p_new_value,
    coalesce(p_meta, '{}'::jsonb),
    auth.uid(),
    now()
  );
end;
$$;


