--
-- Name: can_access_property(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.can_access_property(p_property_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.properties p
    where p.id = p_property_id
      and (
        -- owners/staff (account members)
        public.can_access_account(p.account_id)
        -- tenant assigned to property
        or p.tenant_id = auth.uid()
      )
  );
$$;


