--
-- Name: can_invite_account_role(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.can_invite_account_role(p_account_id uuid, p_target_role text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_inviter_role text;
  v_target_role text := lower(coalesce(p_target_role, ''));
  v_has_admin boolean := false;
begin
  if auth.uid() is null then
    return false;
  end if;

  select exists (
    select 1
    from pg_type t
    join pg_namespace n on n.oid = t.typnamespace
    join pg_enum e on e.enumtypid = t.oid
    where n.nspname = 'public'
      and t.typname = 'account_role'
      and e.enumlabel = 'admin'
  )
  into v_has_admin;

  select lower(am.role::text)
  into v_inviter_role
  from public.account_members am
  where am.account_id = p_account_id
    and am.user_id = auth.uid()
  limit 1;

  if v_target_role = 'owner' then
    return false;
  end if;

  if v_target_role = 'admin' and not v_has_admin then
    v_target_role := 'staff';
  end if;

  if v_inviter_role = 'owner' then
    return v_target_role in ('admin', 'staff', 'tenant', 'contractor');
  end if;

  if v_inviter_role = 'admin' then
    return v_target_role in ('admin', 'staff', 'tenant', 'contractor');
  end if;

  if v_inviter_role = 'staff' then
    return v_target_role in ('staff', 'tenant', 'contractor');
  end if;

  return false;
end;
$$;


ALTER FUNCTION public.can_invite_account_role(p_account_id uuid, p_target_role text) OWNER TO postgres;

