--
-- Name: work_orders; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.work_orders (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    property_id uuid NOT NULL,
    maintenance_request_id uuid,
    contractor_user_id uuid,
    contractor_name text,
    contractor_phone text,
    status text DEFAULT 'assigned'::text NOT NULL,
    scheduled_at timestamp with time zone,
    notes text,
    quote_amount numeric(12,2),
    invoice_amount numeric(12,2),
    created_by uuid DEFAULT auth.uid(),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    assigned_at timestamp with time zone,
    acknowledged_at timestamp with time zone,
    acknowledgement_due_at timestamp with time zone,
    acknowledgement_status text,
    CONSTRAINT work_orders_status_allowed CHECK ((status = ANY (ARRAY['assigned'::text, 'in_progress'::text, 'completed'::text, 'blocked'::text, 'cancelled'::text]))),
    CONSTRAINT work_orders_status_check CHECK ((status = ANY (ARRAY['assigned'::text, 'in_progress'::text, 'completed'::text, 'blocked'::text, 'cancelled'::text])))
);


ALTER TABLE public.work_orders OWNER TO postgres;

--
-- Name: contractor_update_work_order(uuid, text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.contractor_update_work_order(p_work_order_id uuid, p_status text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_scheduled_at timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS public.work_orders
    LANGUAGE plpgsql
    AS $$
declare
  v_row public.work_orders;
begin
  -- Must be the assigned contractor
  select *
  into v_row
  from public.work_orders
  where id = p_work_order_id
    and contractor_user_id = auth.uid();

  if not found then
    raise exception 'Not allowed or work order not found'
      using errcode = '42501';
  end if;

  update public.work_orders
  set
    status       = coalesce(lower(p_status), status),
    notes        = coalesce(p_notes, notes),
    scheduled_at = coalesce(p_scheduled_at, scheduled_at)
  where id = p_work_order_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.contractor_update_work_order(p_work_order_id uuid, p_status text, p_notes text, p_scheduled_at timestamp with time zone) OWNER TO postgres;

--
-- Name: contractor_update_work_order_status(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.contractor_update_work_order_status(p_work_order_id uuid, p_status text, p_notes text DEFAULT NULL::text) RETURNS public.work_orders
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_wo public.work_orders;
begin
  -- Must be logged in
  if auth.uid() is null then
    raise exception 'Not authenticated';
  end if;

  -- Load target row
  select *
  into v_wo
  from public.work_orders
  where id = p_work_order_id;

  if not found then
    raise exception 'Work order not found';
  end if;

  -- Ensure caller is the contractor assigned to this work order
  if v_wo.contractor_user_id is distinct from auth.uid() then
    raise exception 'Not allowed (not assigned contractor)';
  end if;

  -- Enforce allowed status values (transition rules enforced by trigger too)
  if p_status is null or p_status not in ('assigned','in_progress','completed','blocked','cancelled') then
    raise exception 'Invalid status: %', p_status;
  end if;

  -- Update ONLY status + notes
  update public.work_orders
  set status = p_status,
      notes = coalesce(p_notes, notes),
      updated_at = now()
  where id = p_work_order_id
  returning * into v_wo;

  return v_wo;
end;
$$;


ALTER FUNCTION public.contractor_update_work_order_status(p_work_order_id uuid, p_status text, p_notes text) OWNER TO postgres;

--
-- Name: contractor_work_order_cards(uuid[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.contractor_work_order_cards(p_work_order_ids uuid[] DEFAULT NULL::uuid[]) RETURNS TABLE(work_order_id uuid, property_label text, issue_title text, issue_description text, issue_priority text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select
    wo.id as work_order_id,
    trim(
      both ', '
      from concat(coalesce(p.address, ''), case when p.city is not null and p.city <> '' then ', ' || p.city else '' end)
    ) as property_label,
    mr.title as issue_title,
    mr.description as issue_description,
    mr.priority as issue_priority
  from public.work_orders wo
  left join public.properties p
    on p.id = wo.property_id
  left join public.maintenance_requests mr
    on mr.id = wo.maintenance_request_id
  where wo.contractor_user_id = auth.uid()
    and (p_work_order_ids is null or wo.id = any(p_work_order_ids));
$$;


ALTER FUNCTION public.contractor_work_order_cards(p_work_order_ids uuid[]) OWNER TO postgres;

--
-- Name: create_document_stub(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_document_stub(p_account_id uuid, p_filename text) RETURNS TABLE(document_id uuid, storage_path text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_document_id uuid;
  v_path text;
begin
  if public.account_role_for(p_account_id)
       not in ('owner','admin','staff') then
    raise exception 'Not permitted to create documents for this account';
  end if;

  v_document_id := gen_random_uuid();
  v_path := p_account_id::text || '/' || v_document_id::text || '/' || p_filename;

  insert into public.documents (id, account_id, storage_path)
  values (v_document_id, p_account_id, v_path);

  return query
  select v_document_id, v_path;
end;
$$;


ALTER FUNCTION public.create_document_stub(p_account_id uuid, p_filename text) OWNER TO postgres;

--
-- Name: documents; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.documents (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    owner_id uuid,
    property_id uuid,
    tenant_id uuid,
    name text NOT NULL,
    storage_path text NOT NULL,
    mime_type text,
    created_at timestamp with time zone DEFAULT now(),
    size_bytes integer NOT NULL,
    uploaded_by uuid DEFAULT auth.uid(),
    tags public.document_tag[] DEFAULT '{}'::public.document_tag[] NOT NULL,
    account_id uuid NOT NULL,
    scope text NOT NULL,
    visibility text DEFAULT 'staff'::text NOT NULL,
    created_via text DEFAULT 'legacy'::text NOT NULL,
    created_by_user_id uuid,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    upload_status text DEFAULT 'stub'::text NOT NULL,
    uploaded_at timestamp with time zone,
    original_filename text,
    CONSTRAINT documents_mime_check CHECK ((mime_type = ANY (ARRAY['application/pdf'::text, 'image/jpeg'::text, 'image/png'::text, 'image/webp'::text, 'application/msword'::text, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'::text]))),
    CONSTRAINT documents_scope_consistency_check CHECK ((((scope = 'property'::text) AND (property_id IS NOT NULL) AND (tenant_id IS NULL)) OR ((scope = 'tenant'::text) AND (tenant_id IS NOT NULL) AND (property_id IS NULL)) OR ((scope = 'shared'::text) AND (property_id IS NOT NULL) AND (tenant_id IS NOT NULL)) OR ((scope = 'account'::text) AND (property_id IS NULL) AND (tenant_id IS NULL)))),
    CONSTRAINT documents_size_check CHECK ((size_bytes <= 10485760)),
    CONSTRAINT documents_upload_status_check CHECK ((upload_status = ANY (ARRAY['stub'::text, 'uploaded'::text, 'failed'::text]))),
    CONSTRAINT documents_visibility_check CHECK ((visibility = ANY (ARRAY['owner_admin'::text, 'staff'::text, 'tenant'::text, 'private'::text])))
);


ALTER TABLE public.documents OWNER TO postgres;

--
-- Name: create_document_stub(uuid, text, text, uuid, uuid, text, text, integer, public.document_tag[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_document_stub(p_account_id uuid, p_scope text, p_visibility text DEFAULT 'staff'::text, p_property_id uuid DEFAULT NULL::uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_filename text DEFAULT NULL::text, p_mime_type text DEFAULT NULL::text, p_size_bytes integer DEFAULT NULL::integer, p_tags public.document_tag[] DEFAULT '{}'::public.document_tag[]) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_doc_id uuid := gen_random_uuid();
  v_safe_filename text;
  v_storage_path text;
  v_role text;
begin
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  v_role := public.account_role_for(p_account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if p_scope not in ('property','tenant','shared','account') then
    raise exception 'Invalid scope: %', p_scope;
  end if;

  if p_visibility not in ('owner_admin','staff','tenant','private') then
    raise exception 'Invalid visibility: %', p_visibility;
  end if;

  -- Scope consistency checks (matches your new constraint rules)
  if p_scope = 'property' and (p_property_id is null or p_tenant_id is not null) then
    raise exception 'scope=property requires property_id and tenant_id must be null';
  end if;

  if p_scope = 'tenant' and (p_tenant_id is null or p_property_id is not null) then
    raise exception 'scope=tenant requires tenant_id and property_id must be null';
  end if;

  if p_scope = 'shared' and (p_property_id is null or p_tenant_id is null) then
    raise exception 'scope=shared requires both property_id and tenant_id';
  end if;

  if p_scope = 'account' and (p_property_id is not null or p_tenant_id is not null) then
    raise exception 'scope=account requires property_id and tenant_id to be null';
  end if;

  -- File checks (optional on stub, but good to keep consistent)
  if p_size_bytes is not null and p_size_bytes > 10485760 then
    raise exception 'File too large (max 10MB)';
  end if;

  if p_mime_type is not null then
    if p_mime_type not in (
      'application/pdf',
      'image/jpeg',
      'image/png',
      'image/webp',
      'application/msword',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
    ) then
      raise exception 'Invalid mime_type: %', p_mime_type;
    end if;
  end if;

  -- Safe-ish filename (no slashes)
  v_safe_filename := coalesce(nullif(trim(p_filename), ''), 'file');
  v_safe_filename := replace(v_safe_filename, '/', '_');
  v_safe_filename := replace(v_safe_filename, '\', '_');

  -- Account-rooted storage path (recommended going forward)
  v_storage_path := p_account_id::text || '/' || v_doc_id::text || '/' || v_safe_filename;

  insert into public.documents (
    id,
    account_id,
    scope,
    visibility,
    property_id,
    tenant_id,
    name,
    storage_path,
    mime_type,
    size_bytes,
    tags,
    created_via,
    created_by_user_id,
    uploaded_by,
    created_at,
    updated_at
  )
  values (
    v_doc_id,
    p_account_id,
    p_scope,
    p_visibility,
    p_property_id,
    p_tenant_id,
    v_safe_filename,
    v_storage_path,
    p_mime_type,
    coalesce(p_size_bytes, 0),
    coalesce(p_tags, '{}'::public.document_tag[]),
    'rpc',
    auth.uid(),
    auth.uid(),
    now(),
    now()
  )
  returning * into v_doc;

  return v_doc;
end;
$$;


ALTER FUNCTION public.create_document_stub(p_account_id uuid, p_scope text, p_visibility text, p_property_id uuid, p_tenant_id uuid, p_filename text, p_mime_type text, p_size_bytes integer, p_tags public.document_tag[]) OWNER TO postgres;

