ALTER FUNCTION public.create_ledger_entry(p_account_id uuid, p_entry_type text, p_direction text, p_amount numeric, p_currency text, p_property_id uuid, p_tenant_id uuid, p_occurred_at timestamp with time zone, p_notes text) OWNER TO postgres;

--
-- Name: create_notifications(uuid, uuid[], text, text, text, text, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_notifications(p_account_id uuid, p_recipient_user_ids uuid[], p_type text, p_title text, p_body text DEFAULT NULL::text, p_entity_type text DEFAULT NULL::text, p_entity_id uuid DEFAULT NULL::uuid, p_link_path text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  perform public.assert_manage_account_access(p_account_id);

  if p_recipient_user_ids is null or coalesce(array_length(p_recipient_user_ids, 1), 0) = 0 then
    raise exception 'Recipient list cannot be empty';
  end if;

  if exists (
    select 1
    from unnest(p_recipient_user_ids) uid
    left join public.account_members am
      on am.account_id = p_account_id
     and am.user_id = uid
    left join public.contractors c
      on c.account_id = p_account_id
     and c.user_id = uid
     and c.active = true
    left join public.tenants t
      on t.account_id = p_account_id
     and t.user_id = uid
    where uid is null
       or (
         am.user_id is null
         and c.user_id is null
         and t.user_id is null
       )
  ) then
    raise exception 'One or more recipients are not part of this account';
  end if;

  insert into public.notifications (
    account_id,
    recipient_user_id,
    type,
    title,
    body,
    entity_type,
    entity_id,
    link_path,
    metadata
  )
  select
    p_account_id,
    r.uid,
    p_type,
    p_title,
    p_body,
    p_entity_type,
    p_entity_id,
    p_link_path,
    coalesce(p_metadata, '{}'::jsonb)
  from (
    select distinct uid
    from unnest(p_recipient_user_ids) as uid
    where uid is not null
  ) as r;
end;
$$;


ALTER FUNCTION public.create_notifications(p_account_id uuid, p_recipient_user_ids uuid[], p_type text, p_title text, p_body text, p_entity_type text, p_entity_id uuid, p_link_path text, p_metadata jsonb) OWNER TO postgres;

--
-- Name: create_notifications_system(uuid, uuid[], text, text, text, text, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_notifications_system(p_account_id uuid, p_recipient_user_ids uuid[], p_type text, p_title text, p_body text DEFAULT NULL::text, p_entity_type text DEFAULT NULL::text, p_entity_id uuid DEFAULT NULL::uuid, p_link_path text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  if p_recipient_user_ids is null or array_length(p_recipient_user_ids, 1) is null then
    return;
  end if;

  -- Recipients must belong to the account either as:
  -- - account members, OR
  -- - contractors mapped to auth users for that account (active)
  if exists (
    select 1
    from unnest(p_recipient_user_ids) uid
    left join public.account_members am
      on am.account_id = p_account_id
     and am.user_id = uid
    left join public.contractors c
      on c.account_id = p_account_id
     and c.user_id = uid
     and c.active = true
    where am.user_id is null
      and c.user_id is null
  ) then
    raise exception 'One or more recipients are not part of this account';
  end if;

  insert into public.notifications (
    account_id,
    recipient_user_id,
    type,
    title,
    body,
    entity_type,
    entity_id,
    link_path,
    metadata
  )
  select
    p_account_id,
    uid,
    p_type,
    p_title,
    p_body,
    p_entity_type,
    p_entity_id,
    p_link_path,
    coalesce(p_metadata, '{}'::jsonb)
  from unnest(p_recipient_user_ids) as uid;
end;
$$;


ALTER FUNCTION public.create_notifications_system(p_account_id uuid, p_recipient_user_ids uuid[], p_type text, p_title text, p_body text, p_entity_type text, p_entity_id uuid, p_link_path text, p_metadata jsonb) OWNER TO postgres;

--
-- Name: payments; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.payments (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    owner_id uuid NOT NULL,
    property_id uuid NOT NULL,
    tenant_id uuid NOT NULL,
    amount numeric(10,2) NOT NULL,
    status text NOT NULL,
    due_date date NOT NULL,
    paid_at date,
    created_at timestamp with time zone DEFAULT now(),
    account_id uuid NOT NULL,
    CONSTRAINT payments_status_check CHECK ((status = ANY (ARRAY['due'::text, 'paid'::text, 'overdue'::text, 'void'::text])))
);


ALTER TABLE public.payments OWNER TO postgres;

--
-- Name: create_payment(uuid, uuid, uuid, numeric, date, date, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_payment(p_account_id uuid, p_property_id uuid, p_tenant_id uuid, p_amount numeric, p_due_date date, p_paid_at date DEFAULT NULL::date, p_notes text DEFAULT NULL::text) RETURNS public.payments
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_owner_id uuid;
  v_row public.payments;
begin
  -- Guard: only owner/admin/staff can create
  if account_role_for(p_account_id) not in ('owner','admin','staff') then
    raise exception 'Not allowed';
  end if;

  -- Validate property belongs to account and fetch owner_id
  select p.owner_id
    into v_owner_id
  from public.properties p
  where p.id = p_property_id
    and p.account_id = p_account_id;

  if v_owner_id is null then
    raise exception 'Property not found in this account';
  end if;

  -- Validate tenant belongs to account and is active
  if not exists (
    select 1
    from public.tenants t
    where t.id = p_tenant_id
      and t.account_id = p_account_id
      and t.status = 'active'
  ) then
    raise exception 'Tenant not active in this account';
  end if;

  -- Optional: ensure the payment tenant matches property’s current tenant (if you enforce 1 tenant per property)
  -- If you want this strict, uncomment:
  -- if not exists (
  --   select 1 from public.tenants t
  --   where t.id = p_tenant_id and t.property_id = p_property_id
  -- ) then
  --   raise exception 'Tenant is not assigned to this property';
  -- end if;

  insert into public.payments (
    owner_id,
    account_id,
    property_id,
    tenant_id,
    amount,
    due_date,
    paid_at,
    status
  ) values (
    v_owner_id,
    p_account_id,
    p_property_id,
    p_tenant_id,
    p_amount,
    p_due_date,
    p_paid_at,
    -- status will be corrected by trigger tg_payments_set_status(); set a safe default
    'due'
  )
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.create_payment(p_account_id uuid, p_property_id uuid, p_tenant_id uuid, p_amount numeric, p_due_date date, p_paid_at date, p_notes text) OWNER TO postgres;

--
-- Name: create_self_serve_landlord_account(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_self_serve_landlord_account(p_account_name text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_email text;
  v_name text := trim(coalesce(p_account_name, ''));
  v_existing_owner_account_id uuid;
  v_existing_owner_account_name text;
  v_existing_any_non_owner boolean := false;
  v_existing_other_owner_user uuid;
  v_new_account_id uuid;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select lower(u.email::text)
  into v_email
  from auth.users u
  where u.id = v_uid
  limit 1;

  if coalesce(v_email, '') = '' then
    raise exception 'Authenticated email not found';
  end if;

  -- If the user is already owner somewhere, return existing (idempotent).
  select a.id, a.name
  into v_existing_owner_account_id, v_existing_owner_account_name
  from public.account_members am
  join public.accounts a on a.id = am.account_id
  where am.user_id = v_uid
    and lower(am.role::text) = 'owner'
  order by a.created_at asc nulls last, a.id
  limit 1;

  if v_existing_owner_account_id is not null then
    return jsonb_build_object(
      'ok', true,
      'created', false,
      'account_id', v_existing_owner_account_id,
      'account_name', v_existing_owner_account_name,
      'role', 'owner'
    );
  end if;

  -- Guard: users already invited as non-owner cannot self-escalate to owner.
  select exists (
    select 1
    from public.account_members am
    where am.user_id = v_uid
      and lower(am.role::text) <> 'owner'
  )
  into v_existing_any_non_owner;

  if v_existing_any_non_owner then
    raise exception 'This user already belongs to an invited account; landlord self-signup is not allowed';
  end if;

  -- Guard: one landlord(owner) account per email across platform.
  select am.user_id
  into v_existing_other_owner_user
  from public.account_members am
  join auth.users u on u.id = am.user_id
  where lower(u.email::text) = v_email
    and lower(am.role::text) = 'owner'
    and am.user_id <> v_uid
  limit 1;

  if v_existing_other_owner_user is not null then
    raise exception 'This email is already used by an existing landlord account';
  end if;

  if v_name = '' then
    v_name := split_part(v_email, '@', 1);
  end if;

  insert into public.accounts(name, created_by)
  values (v_name, v_uid)
  returning id into v_new_account_id;

  insert into public.account_members(account_id, user_id, role)
  values (v_new_account_id, v_uid, 'owner')
  on conflict (account_id, user_id) do update set role = excluded.role;

  return jsonb_build_object(
    'ok', true,
    'created', true,
    'account_id', v_new_account_id,
    'account_name', v_name,
    'role', 'owner'
  );
end;
$$;


ALTER FUNCTION public.create_self_serve_landlord_account(p_account_name text) OWNER TO postgres;

