--
-- Name: dashboard_hub_extras(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dashboard_hub_extras(p_account_id uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_horizon_days integer DEFAULT 1) RETURNS TABLE(item_key text, item_type text, count_value bigint, property_label text, city text, days_vacant integer, link_path text, sort_order integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  return query
  with cfg as (
    select greatest(1, least(coalesce(p_horizon_days, 1), 30)) as horizon_days
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  due_soon as (
    select count(*)::bigint as due_soon_count
    from payments p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
      and lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
      and p.due_date is not null
      and p.due_date >= current_date
      and p.due_date <= current_date + ((select horizon_days from cfg) || ' days')::interval
  ),
  preventive_due_soon as (
    select count(*)::bigint as task_count
    from public.preventive_maintenance_tasks t
    where t.account_id = p_account_id
      and lower(coalesce(t.status, 'active')) = 'active'
      and t.next_due_date is not null
      and t.next_due_date >= current_date
      and t.next_due_date <= current_date + interval '14 days'
  ),
  preventive_overdue as (
    select count(*)::bigint as task_count
    from public.preventive_maintenance_tasks t
    where t.account_id = p_account_id
      and lower(coalesce(t.status, 'active')) = 'active'
      and t.next_due_date is not null
      and t.next_due_date < current_date
  ),
  blocked_work_orders as (
    select count(*)::bigint as blocked_count
    from public.work_orders_with_flags w
    where w.account_id = p_account_id
      and lower(coalesce(w.status, '')) in ('blocked', 'zablokowane')
  ),
  contractor_ack_overdue as (
    select count(*)::bigint as overdue_count
    from public.work_orders w
    where w.account_id = p_account_id
      and (w.contractor_user_id is not null or nullif(coalesce(w.contractor_name, ''), '') is not null)
      and lower(coalesce(w.status, '')) not in ('completed', 'cancelled', 'zakończone', 'anulowane')
      and coalesce(lower(w.acknowledgement_status), 'pending') <> 'acknowledged'
      and w.acknowledgement_due_at is not null
      and w.acknowledgement_due_at < now()
  ),
  compliance_overdue as (
    select count(*)::bigint as item_count
    from public.compliance_items c
    where c.account_id = p_account_id
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date < current_date
  ),
  compliance_due_soon as (
    select count(*)::bigint as item_count
    from public.compliance_items c
    where c.account_id = p_account_id
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date >= current_date
      and c.due_date <= current_date + interval '30 days'
  ),
  compliance_missing_setup as (
    select count(*)::bigint as property_count
    from public.properties p
    where p.account_id = p_account_id
      and not exists (
        select 1
        from public.compliance_items c
        where c.account_id = p.account_id
          and c.property_id = p.id
      )
  ),
  vacant_long as (
    select
      p.id,
      p.address,
      p.city,
      floor(
        extract(
          epoch from (
            now() - coalesce(
              (
                select max(t.created_at)
                from tenants t
                where t.property_id = p.id
              ),
              p.created_at
            )
          )
        ) / 86400
      )::int as days_vacant
    from properties p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
      and not exists (
        select 1
        from tenants t
        where t.property_id = p.id
      )
    order by days_vacant desc, p.address
    limit 1
  )
  select
    'vacant-long'::text as item_key,
    'vacant_long_summary'::text as item_type,
    null::bigint as count_value,
    vl.address as property_label,
    vl.city,
    vl.days_vacant,
    '/properties?status=vacant&aging=14d'::text as link_path,
    10 as sort_order
  from vacant_long vl
  where vl.days_vacant > 30

  union all

  select
    'due-soon'::text as item_key,
    'due_soon_summary'::text as item_type,
    ds.due_soon_count as count_value,
    null::text as property_label,
    null::text as city,
    null::int as days_vacant,
    ('/finance?status=due&range=' || case when (select horizon_days from cfg) <= 1 then '1d' else '7d' end)::text as link_path,
    20 as sort_order
  from due_soon ds
  where ds.due_soon_count > 0

  union all

  select
    'contractor-ack-overdue'::text,
    'contractor_ack_overdue_summary'::text,
    cao.overdue_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    16 as sort_order
  from contractor_ack_overdue cao
  where cao.overdue_count > 0

  union all

  select
    'compliance-overdue'::text,
    'compliance_overdue_summary'::text,
    co.item_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    17 as sort_order
  from compliance_overdue co
  where co.item_count > 0

  union all

  select
    'preventive-overdue'::text,
    'preventive_overdue_summary'::text,
    po.task_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-kpi'::text,
    18 as sort_order
  from preventive_overdue po
  where po.task_count > 0

  union all

  select
    'compliance-due-soon'::text,
    'compliance_due_summary'::text,
    cds.item_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    19 as sort_order
  from compliance_due_soon cds
  where cds.item_count > 0

  union all

  select
    'compliance-missing-setup'::text,
    'compliance_missing_setup_summary'::text,
    cms.property_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    21 as sort_order
  from compliance_missing_setup cms
  where cms.property_count > 0

  union all

  select
    'preventive-due-soon'::text,
    'preventive_due_summary'::text,
    pd.task_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-kpi'::text,
    22 as sort_order
  from preventive_due_soon pd
  where pd.task_count > 0

  union all

  select
    'blocked-work-orders'::text,
    'blocked_work_order_summary'::text,
    bwo.blocked_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-inbox?woStatus=blocked'::text,
    24 as sort_order
  from blocked_work_orders bwo
  where bwo.blocked_count > 0

  order by sort_order;
end;
$$;


ALTER FUNCTION public.dashboard_hub_extras(p_account_id uuid, p_tenant_id uuid, p_horizon_days integer) OWNER TO postgres;

--
-- Name: dashboard_snapshot(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dashboard_snapshot(p_account_id uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_horizon_days integer DEFAULT 1) RETURNS TABLE(property_count bigint, occupied_count bigint, vacant_count bigint, occupancy_rate integer, tenant_paid_total numeric, tenant_due_total numeric, tenant_overdue_total numeric, tenant_due_overdue_count bigint, overdue_amount numeric, due_soon_count bigint, overdue_current_window_amount numeric, overdue_previous_window_amount numeric, open_requests bigint, open_high_priority bigint, waiting_over_48h bigint, unassigned_work_orders bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  return query
  with cfg as (
    select greatest(1, least(coalesce(p_horizon_days, 1), 30)) as horizon_days
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  scoped_properties as (
    select p.id
    from properties p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  occupied_properties as (
    select sp.id
    from scoped_properties sp
    where exists (
      select 1
      from tenants t
      where t.property_id = sp.id
    )
  ),
  scoped_payments as (
    select
      coalesce(p.amount, 0) as amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.due_date
    from payments p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
  ),
  scoped_requests as (
    select
      lower(coalesce(r.status, '')) as status_norm,
      lower(coalesce(r.priority, '')) as priority_norm,
      r.created_at
    from maintenance_requests r
    where r.account_id = p_account_id
      and (
        v_tenant_id is null
        or r.property_id = (select property_id from tenant_scope)
      )
  ),
  scoped_work_orders as (
    select
      lower(coalesce(w.status, '')) as status_norm,
      w.contractor_user_id
    from work_orders_with_flags w
    where w.account_id = p_account_id
      and (
        v_tenant_id is null
        or w.property_id = (select property_id from tenant_scope)
      )
  ),
  finance as (
    select
      coalesce(sum(case when status_norm in ('paid', 'oplacone', 'opłacone') then amount else 0 end), 0) as tenant_paid_total,
      coalesce(sum(case when status_norm in ('due', 'oczekujace', 'oczekujące', 'pending') then amount else 0 end), 0) as tenant_due_total,
      coalesce(sum(case when status_norm in ('overdue', 'zalegle', 'zaległe') then amount else 0 end), 0) as tenant_overdue_total,
      coalesce(sum(case when status_norm in ('due', 'oczekujace', 'oczekujące', 'pending', 'overdue', 'zalegle', 'zaległe') then 1 else 0 end), 0) as tenant_due_overdue_count,
      coalesce(sum(case when status_norm in ('overdue', 'zalegle', 'zaległe') then amount else 0 end), 0) as overdue_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date >= current_date
             and due_date <= current_date + ((select horizon_days from cfg) || ' days')::interval
            then 1
            else 0
          end
        ),
        0
      ) as due_soon_count,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date <= current_date
             and current_date - due_date <= 7
            then amount
            else 0
          end
        ),
        0
      ) as overdue_current_window_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and current_date - due_date > 7
             and current_date - due_date <= 14
            then amount
            else 0
          end
        ),
        0
      ) as overdue_previous_window_amount
    from scoped_payments
  ),
  maintenance as (
    select
      (select count(*) from scoped_requests where status_norm not in ('closed', 'zamkniete', 'zamknięte')) as open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm not in ('closed', 'zamkniete', 'zamknięte')
          and priority_norm in ('high', 'critical', 'wysoki', 'krytyczny')
      ) as open_high_priority,
      (
        select count(*)
        from scoped_requests
        where status_norm = 'waiting'
          and created_at <= now() - interval '48 hours'
      ) as waiting_over_48h,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked')
          and contractor_user_id is null
      ) as unassigned_work_orders
  )
  select
    (select count(*) from scoped_properties) as property_count,
    (select count(*) from occupied_properties) as occupied_count,
    greatest((select count(*) from scoped_properties) - (select count(*) from occupied_properties), 0) as vacant_count,
    case
      when (select count(*) from scoped_properties) = 0 then 0
      else round(
        ((select count(*) from occupied_properties)::numeric / (select count(*) from scoped_properties)::numeric) * 100
      )::int
    end as occupancy_rate,
    finance.tenant_paid_total,
    finance.tenant_due_total,
    finance.tenant_overdue_total,
    finance.tenant_due_overdue_count,
    finance.overdue_amount,
    finance.due_soon_count,
    finance.overdue_current_window_amount,
    finance.overdue_previous_window_amount,
    maintenance.open_requests,
    maintenance.open_high_priority,
    maintenance.waiting_over_48h,
    maintenance.unassigned_work_orders
  from finance, maintenance;
end;
$$;


ALTER FUNCTION public.dashboard_snapshot(p_account_id uuid, p_tenant_id uuid, p_horizon_days integer) OWNER TO postgres;

--
-- Name: delete_document_and_audit(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_document_and_audit(p_document_id uuid, p_actor_user_id uuid DEFAULT auth.uid()) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner','admin') then
    raise exception 'Not permitted';
  end if;

  insert into public.document_audit_log (
    document_id, action, performed_by, performed_at, account_id, created_at
  )
  values (
    v_doc.id, 'delete', p_actor_user_id, now(), v_doc.account_id, now()
  );

  delete from public.documents where id = v_doc.id;
end;
$$;


ALTER FUNCTION public.delete_document_and_audit(p_document_id uuid, p_actor_user_id uuid) OWNER TO postgres;

--
-- Name: delete_payment(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_payment(p_payment_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  select account_id into v_account_id
  from public.payments
  where id = p_payment_id;

  if v_account_id is null then
    raise exception 'Payment not found';
  end if;

  if account_role_for(v_account_id) not in ('owner','admin') then
    raise exception 'Not allowed';
  end if;

  delete from public.payments where id = p_payment_id;
end;
$$;


ALTER FUNCTION public.delete_payment(p_payment_id uuid) OWNER TO postgres;

--
-- Name: document_notify_uploaded(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.document_notify_uploaded() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_uid uuid;
  v_window_seconds integer := 60; -- throttle window
begin
  -- Only react when upload becomes "uploaded"
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  -- Prevent double-fire on updates
  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  /* -----------------------------
     Message
  ----------------------------- */
  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');
  v_title := 'Dodano dokument';
  v_body := 'Plik: ' || v_name;

  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  /* -----------------------------
     Recipient resolution
  ----------------------------- */

  -- Private → uploader only
  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;

  -- Otherwise → all account members
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  -- Tenant-visible docs → also notify tenant user
  if coalesce(new.visibility, '') = 'tenant'
     and new.tenant_id is not null
  then
    select t.user_id
      into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  /* -----------------------------
     Send notifications (throttled)
  ----------------------------- */
  foreach v_uid in array v_recipients loop
    if public.should_send_notification(
         new.account_id,
         v_uid,
         'document_uploaded',
         'document',
         new.id,
         v_window_seconds
       )
    then
      perform public.create_notifications_system(
        new.account_id,
        array[v_uid],
        'document_uploaded',
        v_title,
        v_body,
        'document',
        new.id,
        '/documents',
        jsonb_build_object(
          'document_id', new.id,
          'property_id', new.property_id,
          'tenant_id', new.tenant_id,
          'scope', new.scope,
          'visibility', new.visibility,
          'name', v_name
        )
      );
    end if;
  end loop;

  return new;
end;
$$;


ALTER FUNCTION public.document_notify_uploaded() OWNER TO postgres;

--
-- Name: documents_notify_uploaded_trg_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.documents_notify_uploaded_trg_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_uid uuid;
  v_window int := 60; -- seconds: adjust if desired
begin
  -- Only notify when the doc becomes uploaded
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  -- If it was already uploaded, skip
  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');
  v_title := 'Dodano dokument';
  v_body := 'Plik: ' || v_name;

  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  -- Private => only uploader
  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  -- If visible to tenant, add tenant's user_id
  if coalesce(new.visibility, '') = 'tenant' and new.tenant_id is not null then
    select t.user_id into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  -- Throttled per-recipient
  foreach v_uid in array v_recipients loop
    if not public.should_throttle_notification(
      new.account_id, v_uid,
      'document_uploaded',
      'document', new.id,
      v_window
    ) then
      perform public.create_notifications_system(
        new.account_id,
        array[v_uid],
        'document_uploaded',
        v_title,
        v_body,
        'document',
        new.id,
        '/documents',
        jsonb_build_object(
          'document_id', new.id,
          'property_id', new.property_id,
          'tenant_id', new.tenant_id,
          'scope', new.scope,
          'visibility', new.visibility,
          'name', v_name
        )
      );
    end if;
  end loop;

  return new;
end;
$$;


ALTER FUNCTION public.documents_notify_uploaded_trg_fn() OWNER TO postgres;

--
-- Name: enforce_work_order_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.enforce_work_order_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_old text := lower(coalesce(old.status, 'assigned'));
  v_new text := lower(coalesce(new.status, 'assigned'));
begin
  -- Only enforce when status changes
  if v_new is not distinct from v_old then
    return new;
  end if;

  if not public.work_order_can_transition(v_old, v_new) then
    raise exception 'Invalid status transition: % -> %', v_old, v_new
      using errcode = 'P0001';
  end if;

  -- Normalize persisted value
  new.status := v_new;
  return new;
end;
$$;


ALTER FUNCTION public.enforce_work_order_status_transition() OWNER TO postgres;

--
-- Name: finalize_document_upload(uuid, integer, text, text, public.document_tag[], uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_document_upload(p_document_id uuid, p_size_bytes integer, p_mime_type text, p_original_filename text DEFAULT NULL::text, p_tags public.document_tag[] DEFAULT NULL::public.document_tag[], p_actor_user_id uuid DEFAULT auth.uid()) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
  v_safe_name text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated: actor_user_id is required';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if p_size_bytes is null or p_size_bytes <= 0 then
    raise exception 'size_bytes must be > 0';
  end if;

  if p_size_bytes > 10485760 then
    raise exception 'File too large (max 10MB)';
  end if;

  if p_mime_type not in (
    'application/pdf',
    'image/jpeg',
    'image/png',
    'image/webp',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
  ) then
    raise exception 'Invalid mime_type: %', p_mime_type;
  end if;

  v_safe_name := coalesce(nullif(trim(p_original_filename), ''), v_doc.name);
  v_safe_name := replace(v_safe_name, '/', '_');
  v_safe_name := replace(v_safe_name, '\', '_');

  update public.documents
  set upload_status = 'uploaded',
      uploaded_at = now(),
      size_bytes = p_size_bytes,
      mime_type = p_mime_type,
      original_filename = coalesce(original_filename, v_safe_name),
      name = v_safe_name,
      tags = coalesce(p_tags, tags),
      uploaded_by = coalesce(uploaded_by, p_actor_user_id),
      created_by_user_id = coalesce(created_by_user_id, p_actor_user_id),
      updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    created_at
  )
  values (
    v_doc.id,
    'upload',
    p_actor_user_id,
    now(),
    v_doc.account_id,
    now()
  );

  return v_doc;
end;
$$;


ALTER FUNCTION public.finalize_document_upload(p_document_id uuid, p_size_bytes integer, p_mime_type text, p_original_filename text, p_tags public.document_tag[], p_actor_user_id uuid) OWNER TO postgres;

--
-- Name: finance_snapshot(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finance_snapshot(p_account_id uuid, p_tenant_id uuid DEFAULT NULL::uuid) RETURNS TABLE(total_income numeric, overdue_income numeric, expected_income numeric, property_finance jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  return query
  with tenant_scope as (
    select t.property_id
    from public.tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  scoped_payments as (
    select
      p.id,
      p.property_id,
      p.tenant_id,
      coalesce(p.amount, 0) as amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.paid_at,
      p.due_date
    from payments p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
  ),
  scoped_properties as (
    select
      pr.id,
      pr.address,
      pr.city,
      coalesce(pr.rent, 0) as rent
    from properties pr
    where pr.account_id = p_account_id
      and (
        v_tenant_id is null
        or pr.id = (select property_id from tenant_scope)
      )
  ),
  finance_totals as (
    select
      coalesce(
        sum(
          case
            when paid_at is not null or status_norm in ('paid', 'oplacone', 'opłacone')
            then amount
            else 0
          end
        ),
        0
      ) as total_income,
      coalesce(
        sum(
          case
            when not (paid_at is not null or status_norm in ('paid', 'oplacone', 'opłacone'))
             and (
               status_norm in ('overdue', 'zalegle', 'zaległe')
               or (due_date is not null and due_date < current_date)
             )
            then amount
            else 0
          end
        ),
        0
      ) as overdue_income,
      coalesce(
        sum(
          case
            when not (paid_at is not null or status_norm in ('paid', 'oplacone', 'opłacone'))
            then amount
            else 0
          end
        ),
        0
      ) as expected_income
    from scoped_payments
  ),
  property_rows as (
    select
      pr.id as property_id,
      pr.address,
      pr.city,
      pr.rent,
      coalesce(
        sum(
          case
            when sp.paid_at is not null
             and date_trunc('month', sp.paid_at::timestamp) = date_trunc('month', current_date::timestamp)
            then sp.amount
            else 0
          end
        ),
        0
      ) as paid,
      greatest(
        pr.rent - coalesce(
          sum(
            case
              when sp.paid_at is not null
               and date_trunc('month', sp.paid_at::timestamp) = date_trunc('month', current_date::timestamp)
              then sp.amount
              else 0
            end
          ),
          0
        ),
        0
      ) as remaining
    from scoped_properties pr
    left join scoped_payments sp
      on sp.property_id = pr.id
    group by pr.id, pr.address, pr.city, pr.rent
  ),
  property_json as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'propertyId', property_id,
          'address', address,
          'city', city,
          'rent', rent,
          'paid', paid,
          'remaining', remaining,
          'paymentStatus',
            case
              when paid = 0 then 'Zaległe'
              when paid < rent then 'Częściowo'
              else 'Opłacone'
            end
        )
        order by address
      ),
      '[]'::jsonb
    ) as property_finance
    from property_rows
  )
  select
    finance_totals.total_income,
    finance_totals.overdue_income,
    finance_totals.expected_income,
    property_json.property_finance
  from finance_totals, property_json;
end;
$$;


ALTER FUNCTION public.finance_snapshot(p_account_id uuid, p_tenant_id uuid) OWNER TO postgres;

--
-- Name: fn_documents_notify_uploaded(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_documents_notify_uploaded() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  v_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_vars jsonb;
begin
  -- Only when upload_status becomes uploaded
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  -- If already uploaded previously, ignore repeated updates
  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');

  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  -- Recipients logic (same as your current)
  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  -- Tenant visibility adds tenant user (same as your current)
  if coalesce(new.visibility, '') = 'tenant' and new.tenant_id is not null then
    select t.user_id into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  -- i18n vars
  v_vars := jsonb_build_object(
    'name', v_name,
    'document_id', new.id,
    'property_id', new.property_id,
    'tenant_id', new.tenant_id,
    'scope', new.scope,
    'visibility', new.visibility
  );

  -- i18n title/body (per account language)
  select t.title, t.body
    into v_title, v_body
  from public.get_notification_text(new.account_id, 'document_uploaded', v_vars) t;

  perform public.create_notifications_system(
    new.account_id,
    v_recipients,
    'document_uploaded',
    v_title,
    v_body,
    'document',
    new.id,
    '/documents?doc=' || new.id::text,
    v_vars
  );

  return new;
end;
$$;


ALTER FUNCTION public.fn_documents_notify_uploaded() OWNER TO postgres;

--
-- Name: get_account_owner_contact(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_account_owner_contact(p_account_id uuid) RETURNS TABLE(owner_user_id uuid, owner_email text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_has_direct_access boolean := false;
  v_is_root_operator boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select exists (
    select 1
    from public.account_members am
    where am.account_id = p_account_id
      and am.user_id = v_uid
  )
  into v_has_direct_access;

  select exists (
    select 1
    from public.account_members am
    join public.accounts a on a.id = am.account_id
    where am.user_id = v_uid
      and coalesce(a.is_root, false) = true
  )
  into v_is_root_operator;

  if not v_has_direct_access and not v_is_root_operator then
    raise exception 'Access denied';
  end if;

  return query
  with owner_member as (
    select
      am.user_id as owner_user_id,
      lower(u.email::text) as owner_email
    from public.account_members am
    join auth.users u on u.id = am.user_id
    where am.account_id = p_account_id
      and lower(am.role::text) = 'owner'
    order by am.user_id
    limit 1
  ),
  owner_creator as (
    select
      a.created_by as owner_user_id,
      lower(u.email::text) as owner_email
    from public.accounts a
    join auth.users u on u.id = a.created_by
    where a.id = p_account_id
    limit 1
  )
  select *
  from owner_member
  union all
  select *
  from owner_creator
  where not exists (select 1 from owner_member)
  limit 1;
end;
$$;


ALTER FUNCTION public.get_account_owner_contact(p_account_id uuid) OWNER TO postgres;

