--
-- Name: get_notification_text(uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_notification_text(p_account_id uuid, p_type text, p_vars jsonb) RETURNS TABLE(title text, body text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  v_lang text;
  v_title_t text;
  v_body_t text;
begin
  select a.language into v_lang
  from public.accounts a
  where a.id = p_account_id;

  v_lang := coalesce(nullif(v_lang, ''), 'pl');

  -- Try account language first
  select t.title_template, t.body_template
    into v_title_t, v_body_t
  from public.notification_templates t
  where t.type = p_type and t.lang = v_lang;

  -- Fallback to PL
  if v_title_t is null then
    select t.title_template, t.body_template
      into v_title_t, v_body_t
    from public.notification_templates t
    where t.type = p_type and t.lang = 'pl';
  end if;

  -- Last fallback: raw type
  if v_title_t is null then
    v_title_t := p_type;
    v_body_t := null;
  end if;

  title := public.render_template(v_title_t, p_vars);
  body  := case when v_body_t is null then null else public.render_template(v_body_t, p_vars) end;

  return next;
end;
$$;


ALTER FUNCTION public.get_notification_text(p_account_id uuid, p_type text, p_vars jsonb) OWNER TO postgres;

--
-- Name: get_property_finance(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_property_finance(p_account_id uuid) RETURNS TABLE(property_id uuid, total_in numeric, total_out numeric, net numeric, payments_in numeric)
    LANGUAGE sql STABLE
    AS $$
  select
    property_id,
    coalesce(sum(case when direction = 'in'  then amount end), 0)::numeric as total_in,
    coalesce(sum(case when direction = 'out' then amount end), 0)::numeric as total_out,
    coalesce(sum(case when direction = 'in'  then amount else -amount end), 0)::numeric as net,
    coalesce(sum(case when entry_type='payment' and direction='in' then amount end), 0)::numeric as payments_in
  from public.ledger_entries
  where account_id = p_account_id
  group by property_id
  order by net desc nulls last;
$$;


