--

CREATE FUNCTION public.is_assigned_contractor(p_work_order_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE
    AS $$
  select exists (
    select 1
    from public.work_orders wo
    where wo.id = p_work_order_id
      and wo.contractor_user_id = p_user_id
  );
$$;


