-- Name: is_payment_tenant(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_payment_tenant(p_payment_id uuid) RETURNS boolean
    LANGUAGE sql STABLE
    AS $$
  select exists (
    select 1
    from public.payments p
    join public.tenants t
      on t.id = p.tenant_id
     and t.account_id = p.account_id
    where p.id = p_payment_id
      and t.user_id = auth.uid()
      and t.archived_at is null
      and t.status in ('active','accepted_pending_signing')
  );
$$;


