--
-- Name: is_uuid_text(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_uuid_text(p_value text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    AS $_$
  select p_value ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$';
$_$;


ALTER FUNCTION public.is_uuid_text(p_value text) OWNER TO postgres;

