-- Name: FUNCTION is_uuid_text(p_value text); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.is_uuid_text(p_value text) IS 'Returns true if the supplied text looks like a UUID.';


--
-- Name: lease_attention_items(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.lease_attention_items(p_account_id uuid, p_limit integer DEFAULT 10, p_expiring_days integer DEFAULT 60) RETURNS TABLE(item_key text, item_type text, property_label text, tenant_label text, lease_end_date date, days_until_end integer, link_path text, sort_order integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  perform public.assert_manage_account_access(p_account_id);

  return query
  with cfg as (
    select
      greatest(1, least(coalesce(p_limit, 10), 50)) as max_items,
      greatest(1, least(coalesce(p_expiring_days, 60), 365)) as expiring_days
  ),
  scoped_leases as (
    select
      l.id,
      l.tenant_id,
      l.lease_end_date,
      lower(coalesce(l.renewal_status, 'active')) as renewal_status,
      coalesce(p.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label,
      (l.lease_end_date - current_date)::int as days_until_end
    from public.leases l
    left join public.properties p on p.id = l.property_id
    left join public.tenants t on t.id = l.tenant_id
    where l.account_id = p_account_id
  ),
  items as (
    select
      'lease-expired-' || sl.id::text as item_key,
      'lease_expired'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      10 as sort_order
    from scoped_leases sl
    where sl.lease_end_date < current_date
      and sl.renewal_status not in ('renewed', 'ended')

    union all

    select
      'lease-expiring-' || sl.id::text as item_key,
      'lease_expiring_soon'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      20 as sort_order
    from scoped_leases sl
    where sl.lease_end_date >= current_date
      and sl.lease_end_date <= current_date + (select expiring_days from cfg)
      and sl.renewal_status not in ('renewed', 'ended')

    union all

    select
      'lease-renewal-' || sl.id::text as item_key,
      'lease_renewal_in_progress'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      30 as sort_order
    from scoped_leases sl
    where sl.renewal_status = 'renewal_in_progress'
  )
  select
    i.item_key,
    i.item_type,
    i.property_label,
    i.tenant_label,
    i.lease_end_date,
    i.days_until_end,
    i.link_path,
    i.sort_order
  from items i
  order by 8, 5 asc nulls last, 1
  limit (select max_items from cfg);
end;
$$;


ALTER FUNCTION public.lease_attention_items(p_account_id uuid, p_limit integer, p_expiring_days integer) OWNER TO postgres;

--
-- Name: log_document_delete(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_document_delete() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
begin
  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    account_id,
    created_at
  )
  values (
    old.id,
    'delete',
    auth.uid(),
    old.account_id,
    now()
  );

  return old;
end;
$$;


