--
-- Name: log_security_event(uuid, text, text, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_security_event(p_account_id uuid, p_action text, p_entity_type text, p_entity_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_actor_user_id uuid;
  v_row_id uuid;
  v_existing_row_id uuid;
  v_action text;
  v_entity_type text;
  v_is_service_role boolean := coalesce(auth.role(), '') = 'service_role';
begin
  v_actor_user_id := auth.uid();

  v_action := lower(trim(coalesce(p_action, '')));
  v_entity_type := lower(trim(coalesce(p_entity_type, '')));

  if nullif(v_action, '') is null then
    raise exception 'Missing action';
  end if;

  if nullif(v_entity_type, '') is null then
    raise exception 'Missing entity type';
  end if;

  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if v_is_service_role then
    v_account_id := p_account_id;
  elsif public.user_can_manage_account(p_account_id) then
    v_account_id := p_account_id;
  elsif v_actor_user_id is not null
    and exists (
      select 1
      from public.account_members am
      where am.account_id = p_account_id
        and am.user_id = v_actor_user_id
    )
  then
    if v_action = 'invite_accepted' and v_entity_type in ('account_invitation', 'account_invitations') then
      if not exists (
        select 1
        from public.account_invitations ai
        where ai.id = p_entity_id
          and ai.account_id = p_account_id
          and ai.accepted_by = v_actor_user_id
          and ai.accepted_at is not null
      ) then
        raise exception 'Access denied';
      end if;

      select sal.id
      into v_existing_row_id
      from public.security_audit_ledger sal
      where sal.account_id = p_account_id
        and sal.actor_user_id = v_actor_user_id
        and sal.action = v_action
        and sal.entity_id is not distinct from p_entity_id
      order by sal.created_at desc
      limit 1;

      if v_existing_row_id is not null then
        return v_existing_row_id;
      end if;

      v_account_id := p_account_id;
    elsif v_action = 'role_changed'
      and v_entity_type = 'account_member'
      and p_entity_id = v_actor_user_id
      and coalesce(p_metadata->>'change_source', '') = 'invite_acceptance'
    then
      if not exists (
        select 1
        from public.account_members am
        where am.account_id = p_account_id
          and am.user_id = v_actor_user_id
          and lower(am.role::text) = lower(coalesce(p_metadata->>'new_role', ''))
      ) then
        raise exception 'Access denied';
      end if;

      if not exists (
        select 1
        from public.account_invitations ai
        where ai.id::text = coalesce(p_metadata->>'invite_id', '')
          and ai.account_id = p_account_id
          and ai.accepted_by = v_actor_user_id
          and ai.accepted_at is not null
      ) then
        raise exception 'Access denied';
      end if;

      select sal.id
      into v_existing_row_id
      from public.security_audit_ledger sal
      where sal.account_id = p_account_id
        and sal.actor_user_id = v_actor_user_id
        and sal.action = v_action
        and sal.entity_id is not distinct from p_entity_id
        and coalesce(sal.metadata->>'change_source', '') = 'invite_acceptance'
        and coalesce(sal.metadata->>'new_role', '') = coalesce(p_metadata->>'new_role', '')
      order by sal.created_at desc
      limit 1;

      if v_existing_row_id is not null then
        return v_existing_row_id;
      end if;

      v_account_id := p_account_id;
    else
      raise exception 'Access denied';
    end if;
  else
    raise exception 'Access denied';
  end if;

  insert into public.security_audit_ledger (
    account_id,
    actor_user_id,
    action,
    entity_type,
    entity_id,
    metadata
  )
  values (
    v_account_id,
    v_actor_user_id,
    v_action,
    v_entity_type,
    p_entity_id,
    coalesce(p_metadata, '{}'::jsonb)
  )
  returning id into v_row_id;

  return v_row_id;
end;
$$;


ALTER FUNCTION public.log_security_event(p_account_id uuid, p_action text, p_entity_type text, p_entity_id uuid, p_metadata jsonb) OWNER TO postgres;

--
-- Name: FUNCTION log_security_event(p_account_id uuid, p_action text, p_entity_type text, p_entity_id uuid, p_metadata jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.log_security_event(p_account_id uuid, p_action text, p_entity_type text, p_entity_id uuid, p_metadata jsonb) IS 'Canonical append-only writer for security_audit_ledger rows. Validates manager/root access for the target account, allows tightly scoped self-service invite acceptance logging, and records auth.uid() as actor_user_id when available.';


--
-- Name: maintenance_attention_needed(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maintenance_attention_needed(p_account_id uuid) RETURNS TABLE(item_type text, maintenance_request_id uuid, work_order_id uuid, request_status text, work_order_status text, priority text, title text, property_label text, created_at timestamp with time zone, age_hours numeric)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with req as (
    select
      mr.id,
      mr.status,
      mr.priority,
      mr.title,
      mr.created_at,
      mr.property_id
    from public.maintenance_requests mr
    where mr.account_id = p_account_id
  ),
  wo as (
    select
      w.id,
      w.status,
      w.contractor_user_id,
      w.maintenance_request_id,
      w.created_at
    from public.work_orders w
    where w.account_id = p_account_id
  ),
  req_with_property as (
    select
      r.id,
      r.status,
      r.priority,
      r.title,
      r.created_at,
      coalesce(
        concat_ws(', ', p.address, p.city),
        r.property_id::text
      ) as property_label
    from req r
    left join public.properties p
      on p.id = r.property_id
     and p.account_id = p_account_id
  )

  -- 1) waiting > 48h
  select
    'stuck_waiting_over_48h'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) = 'waiting'
    and r.created_at < now() - interval '48 hours'

  union all

  -- 2) high priority unresolved
  select
    'high_priority_unresolved'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) <> 'closed'
    and lower(coalesce(r.priority::text, '')) in ('high', 'urgent')

  union all

  -- 3) request without work order
  select
    'request_without_work_order'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) <> 'closed'
    and not exists (
      select 1
      from wo
      where wo.maintenance_request_id = r.id
    )

  union all

  -- 4) work order without contractor
  select
    'work_order_without_contractor'::text as item_type,
    r.id::uuid as maintenance_request_id,
    w.id::uuid as work_order_id,
    r.status::text as request_status,
    w.status::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    least(r.created_at, w.created_at)::timestamptz as created_at,
    round((extract(epoch from (now() - least(r.created_at, w.created_at))) / 3600.0)::numeric, 1) as age_hours
  from wo w
  join req_with_property r
    on r.id = w.maintenance_request_id
  where lower(coalesce(w.status::text, '')) in ('assigned', 'in_progress')
    and w.contractor_user_id is null

  order by created_at asc;
$$;


ALTER FUNCTION public.maintenance_attention_needed(p_account_id uuid) OWNER TO postgres;

--
-- Name: maintenance_dashboard_stats(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maintenance_dashboard_stats(p_account_id uuid) RETURNS TABLE(open_requests bigint, active_work_orders bigint, awaiting_action bigint, resolved_pending_closure bigint, open_high_priority bigint, stuck_waiting_over_48h bigint, requests_without_work_order bigint, work_orders_without_contractor bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with req as (
    select
      mr.id,
      mr.status,
      mr.priority,
      mr.created_at
    from public.maintenance_requests mr
    where mr.account_id = p_account_id
  ),
  wo as (
    select
      w.id,
      w.status,
      w.contractor_user_id,
      w.maintenance_request_id,
      w.created_at
    from public.work_orders w
    where w.account_id = p_account_id
  )
  select
    (
      select count(*)
      from req
      where lower(coalesce(status, '')) <> 'closed'
    ) as open_requests,

    (
      select count(*)
      from wo
      where lower(coalesce(status, '')) = 'in_progress'
    ) as active_work_orders,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'waiting'
    ) as awaiting_action,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'resolved'
    ) as resolved_pending_closure,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) <> 'closed'
        and lower(coalesce(priority, '')) in ('high', 'urgent')
    ) as open_high_priority,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'waiting'
        and created_at < now() - interval '48 hours'
    ) as stuck_waiting_over_48h,

    (
      select count(*)
      from req r
      where lower(coalesce(r.status, '')) <> 'closed'
        and not exists (
          select 1
          from wo
          where wo.maintenance_request_id = r.id
        )
    ) as requests_without_work_order,

    (
      select count(*)
      from wo
      where lower(coalesce(status, '')) in ('assigned', 'in_progress')
        and contractor_user_id is null
    ) as work_orders_without_contractor
$$;


ALTER FUNCTION public.maintenance_dashboard_stats(p_account_id uuid) OWNER TO postgres;

--
-- Name: maintenance_kpi_snapshot(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maintenance_kpi_snapshot(p_account_id uuid) RETURNS TABLE(open_requests bigint, active_work_orders bigint, awaiting_action bigint, resolved_pending_closure bigint, open_high_priority bigint, triage_over_24h bigint, contractor_ack_overdue bigint, stalled_repairs bigint, long_running_repairs bigint, repeat_repair_properties bigint, req_by_status jsonb, wo_by_status jsonb, aging jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  perform public.assert_manage_account_access(p_account_id);

  return query
  with req as (
    select
      id,
      property_id,
      lower(coalesce(status, '')) as status_norm,
      lower(coalesce(priority, '')) as priority_norm,
      created_at,
      updated_at
    from maintenance_requests
    where account_id = p_account_id
  ),
  wo as (
    select
      id,
      property_id,
      maintenance_request_id,
      contractor_user_id,
      contractor_name,
      acknowledgement_due_at,
      acknowledged_at,
      lower(coalesce(acknowledgement_status, '')) as acknowledgement_status_norm,
      lower(coalesce(status, '')) as status_norm,
      created_at,
      updated_at
    from work_orders
    where account_id = p_account_id
  ),
  recent_repair_properties as (
    select property_id
    from req
    where property_id is not null
      and created_at >= now() - interval '90 days'
    group by property_id
    having count(*) >= 3
  ),
  status_counts as (
    select
      jsonb_build_object(
        'open', (select count(*) from req where status_norm = 'open'),
        'in_progress', (select count(*) from req where status_norm = 'in_progress'),
        'waiting', (select count(*) from req where status_norm = 'waiting'),
        'resolved', (select count(*) from req where status_norm = 'resolved'),
        'closed', (select count(*) from req where status_norm = 'closed')
      ) as req_by_status,
      jsonb_build_object(
        'assigned', (select count(*) from wo where status_norm = 'assigned'),
        'in_progress', (select count(*) from wo where status_norm = 'in_progress'),
        'completed', (select count(*) from wo where status_norm = 'completed'),
        'cancelled', (select count(*) from wo where status_norm = 'cancelled')
      ) as wo_by_status
  ),
  aging_counts as (
    select jsonb_build_object(
      'b0_24',
        (select count(*) from req where status_norm <> 'closed' and created_at > now() - interval '24 hours'),
      'b24_48',
        (select count(*) from req where status_norm <> 'closed' and created_at <= now() - interval '24 hours' and created_at > now() - interval '48 hours'),
      'b48_72',
        (select count(*) from req where status_norm <> 'closed' and created_at <= now() - interval '48 hours' and created_at > now() - interval '72 hours'),
      'b72_plus',
        (select count(*) from req where status_norm <> 'closed' and created_at <= now() - interval '72 hours')
    ) as aging
  )
  select
    (select count(*) from req where status_norm <> 'closed') as open_requests,
    (select count(*) from wo where status_norm = 'in_progress') as active_work_orders,
    (select count(*) from req where status_norm = 'waiting') as awaiting_action,
    (select count(*) from req where status_norm = 'resolved') as resolved_pending_closure,
    (
      select count(*)
      from req
      where status_norm <> 'closed'
        and priority_norm in ('high', 'urgent')
    ) as open_high_priority,
    (
      select count(*)
      from req r
      where r.status_norm = 'open'
        and r.created_at <= now() - interval '24 hours'
        and not exists (
          select 1
          from wo
          where wo.maintenance_request_id = r.id
        )
    ) as triage_over_24h,
    (
      select count(*)
      from wo
      where status_norm not in ('completed', 'cancelled', 'zakończone', 'anulowane')
        and (contractor_user_id is not null or nullif(coalesce(contractor_name, ''), '') is not null)
        and acknowledgement_due_at is not null
        and acknowledgement_due_at < now()
        and acknowledgement_status_norm <> 'acknowledged'
        and acknowledged_at is null
    ) as contractor_ack_overdue,
    (
      select count(*)
      from wo
      where status_norm in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
        and coalesce(updated_at, created_at) <= now() - interval '72 hours'
    ) as stalled_repairs,
    (
      select count(*)
      from wo
      where status_norm not in ('completed', 'cancelled', 'zakończone', 'anulowane')
        and created_at <= now() - interval '14 days'
    ) as long_running_repairs,
    (select count(*) from recent_repair_properties) as repeat_repair_properties,
    status_counts.req_by_status,
    status_counts.wo_by_status,
    aging_counts.aging
  from status_counts, aging_counts;
end;
$$;


ALTER FUNCTION public.maintenance_kpi_snapshot(p_account_id uuid) OWNER TO postgres;

--
-- Name: mark_payment_paid(uuid, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_payment_paid(p_payment_id uuid, p_paid_at date DEFAULT CURRENT_DATE) RETURNS public.payments
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_pay public.payments;
  v_role text;
begin
  select * into v_pay
  from public.payments
  where id = p_payment_id;

  if not found then
    raise exception 'Payment not found';
  end if;

  v_role := public.account_role_for(v_pay.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  update public.payments
  set paid_at = coalesce(p_paid_at, current_date)
  where id = p_payment_id
  returning * into v_pay;

  -- ledger sync handled by trigger
  return v_pay;
end;
$$;


ALTER FUNCTION public.mark_payment_paid(p_payment_id uuid, p_paid_at date) OWNER TO postgres;

--
-- Name: mark_payment_unpaid(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_payment_unpaid(p_payment_id uuid) RETURNS public.payments
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_row public.payments;
begin
  select * into v_row
  from public.payments
  where id = p_payment_id;

  if v_row.id is null then
    raise exception 'Payment not found';
  end if;

  if account_role_for(v_row.account_id) not in ('owner','admin','staff') then
    raise exception 'Not allowed';
  end if;

  update public.payments
  set paid_at = null
  where id = p_payment_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.mark_payment_unpaid(p_payment_id uuid) OWNER TO postgres;

--
-- Name: notifications_mark_all_read(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notifications_mark_all_read(p_account_id uuid DEFAULT NULL::uuid) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_count integer := 0;
begin
  -- Optional: if account_id is provided, only mark notifications in that account
  if p_account_id is not null then
    update public.notifications n
    set is_read = true,
        read_at = now()
    where n.recipient_user_id = auth.uid()
      and n.account_id = p_account_id
      and n.is_read = false;

  else
    update public.notifications n
    set is_read = true,
        read_at = now()
    where n.recipient_user_id = auth.uid()
      and n.is_read = false;
  end if;

  get diagnostics v_count = row_count;
  return v_count;
end;
$$;


ALTER FUNCTION public.notifications_mark_all_read(p_account_id uuid) OWNER TO postgres;

--
-- Name: playbook_status_snapshot(uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.playbook_status_snapshot(p_account_id uuid, p_recent_limit integer DEFAULT 12) RETURNS TABLE(settings jsonb, open_run_counts jsonb, recent_runs jsonb, recent_resolved_runs jsonb, recent_executions jsonb, open_runs integer, last_run_at timestamp with time zone, last_run_status text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  perform public.assert_manage_account_access(p_account_id);

  return query
  with cfg as (
    select greatest(1, least(coalesce(p_recent_limit, 12), 50)) as recent_limit
  ),
  settings_rows as (
    select
      ars.rule_id,
      ars.enabled,
      ars.config,
      ars.updated_at
    from public.automation_rule_settings ars
    where ars.account_id = p_account_id
  ),
  open_run_count_rows as (
    select
      ar.rule_id,
      count(*)::int as run_count
    from public.automation_runs ar
    where ar.account_id = p_account_id
      and lower(coalesce(ar.state, 'open')) = 'open'
    group by ar.rule_id
  ),
  recent_run_rows as (
    select
      ar.id,
      ar.rule_id,
      ar.source_key,
      ar.state,
      ar.severity,
      ar.title,
      ar.body,
      ar.entity_type,
      ar.entity_id,
      ar.link_path,
      ar.details,
      ar.first_triggered_at,
      ar.last_triggered_at,
      ar.resolved_at,
      ar.created_at,
      ar.updated_at
    from public.automation_runs ar
    where ar.account_id = p_account_id
    order by ar.last_triggered_at desc nulls last, ar.created_at desc
    limit (select recent_limit from cfg)
  ),
  recent_resolved_rows as (
    select
      ar.id,
      ar.rule_id,
      ar.source_key,
      ar.state,
      ar.severity,
      ar.title,
      ar.body,
      ar.entity_type,
      ar.entity_id,
      ar.link_path,
      ar.details,
      ar.first_triggered_at,
      ar.last_triggered_at,
      ar.resolved_at,
      ar.created_at,
      ar.updated_at
    from public.automation_runs ar
    where ar.account_id = p_account_id
      and lower(coalesce(ar.state, 'open')) = 'resolved'
    order by ar.resolved_at desc nulls last, ar.last_triggered_at desc nulls last
    limit (select recent_limit from cfg)
  ),
  recent_execution_rows as (
    select
      ael.id,
      ael.rule_id,
      ael.event_key,
      ael.execution_type,
      ael.status,
      ael.entity_type,
      ael.entity_id,
      ael.title,
      ael.details,
      ael.executed_at,
      ael.created_at
    from public.automation_execution_log ael
    where ael.account_id = p_account_id
    order by ael.executed_at desc nulls last, ael.created_at desc
    limit (select recent_limit from cfg)
  ),
  latest_sync as (
    select
      ael.executed_at,
      ael.status
    from public.automation_execution_log ael
    where ael.account_id = p_account_id
      and ael.execution_type in ('rule_evaluated', 'rule_evaluated_dry_run', 'account_sync_failed')
    order by ael.executed_at desc nulls last, ael.created_at desc
    limit 1
  )
  select
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'rule_id', sr.rule_id,
            'enabled', sr.enabled,
            'config', sr.config,
            'updated_at', sr.updated_at
          )
          order by sr.rule_id
        )
        from settings_rows sr
      ),
      '[]'::jsonb
    ) as settings,
    coalesce(
      (
        select jsonb_object_agg(orc.rule_id, orc.run_count)
        from open_run_count_rows orc
      ),
      '{}'::jsonb
    ) as open_run_counts,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rr) order by rr.last_triggered_at desc nulls last, rr.created_at desc)
        from recent_run_rows rr
      ),
      '[]'::jsonb
    ) as recent_runs,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rrr) order by rrr.resolved_at desc nulls last, rrr.last_triggered_at desc nulls last)
        from recent_resolved_rows rrr
      ),
      '[]'::jsonb
    ) as recent_resolved_runs,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rex) order by rex.executed_at desc nulls last, rex.created_at desc)
        from recent_execution_rows rex
      ),
      '[]'::jsonb
    ) as recent_executions,
    coalesce(
      (
        select sum(orc.run_count)::int
        from open_run_count_rows orc
      ),
      0
    ) as open_runs,
    (select ls.executed_at from latest_sync ls) as last_run_at,
    coalesce((select ls.status from latest_sync ls), 'recorded') as last_run_status;
end;
$$;


ALTER FUNCTION public.playbook_status_snapshot(p_account_id uuid, p_recent_limit integer) OWNER TO postgres;

--
-- Name: portfolio_attention_items(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.portfolio_attention_items(p_account_id uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 10) RETURNS TABLE(item_key text, item_type text, property_label text, city text, amount numeric, days_vacant integer, request_title text, link_path text, sort_order integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  return query
  with cfg as (
    select greatest(1, least(coalesce(p_limit, 10), 50)) as max_items
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  scoped_properties as (
    select
      p.id,
      p.address,
      p.city,
      p.created_at,
      not exists (
        select 1
        from tenants t
        where t.property_id = p.id
      ) as is_vacant
    from properties p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  vacant_properties as (
    select
      sp.id,
      sp.address,
      sp.city,
      floor(
        extract(
          epoch from (
            now() - coalesce(
              (
                select max(t.created_at)
                from tenants t
                where t.property_id = sp.id
              ),
              sp.created_at
            )
          )
        ) / 86400
      )::int as days_vacant
    from scoped_properties sp
    where sp.is_vacant
  ),
  overdue_payments as (
    select
      p.id,
      coalesce(pr.address, '—') as property_label,
      coalesce(pr.city, '') as city,
      coalesce(p.amount, 0) as amount
    from payments p
    left join properties pr on pr.id = p.property_id
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
      and (
        lower(coalesce(p.status, '')) in ('overdue', 'zalegle', 'zaległe')
        or (
          lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
          and p.due_date is not null
          and p.due_date < current_date
        )
      )
    order by p.due_date asc nulls last, p.created_at desc nulls last
    limit 4
  ),
  due_soon_payments as (
    select
      p.id,
      coalesce(pr.address, '—') as property_label,
      coalesce(pr.city, '') as city,
      coalesce(p.amount, 0) as amount
    from payments p
    left join properties pr on pr.id = p.property_id
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
      and lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
      and p.due_date is not null
      and p.due_date >= current_date
      and p.due_date <= current_date + interval '7 days'
    order by p.due_date asc, p.created_at desc nulls last
    limit 4
  ),
  high_priority_requests as (
    select
      r.id,
      r.title
    from maintenance_requests r
    where r.account_id = p_account_id
      and (
        v_tenant_id is null
        or r.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(r.status, '')) not in ('closed', 'zamkniete', 'zamknięte')
      and lower(coalesce(r.priority, '')) in ('high', 'urgent', 'critical', 'wysoki', 'krytyczny')
    order by r.created_at desc
    limit 4
  ),
  items as (
    select *
    from (
      select
        'vacant-' || vp.id::text as item_key,
        'vacant'::text as item_type,
        vp.address as property_label,
        vp.city,
        null::numeric as amount,
        vp.days_vacant,
        null::text as request_title,
        '/properties?status=vacant'::text as link_path,
        10 as sort_order
      from vacant_properties vp
      where v_tenant_id is null
      order by vp.days_vacant desc, vp.address
      limit 4
    ) vacant_items

    union all

    select *
    from (
      select
        'vacant-long-' || vp.id::text as item_key,
        'vacant_long'::text as item_type,
        vp.address as property_label,
        vp.city,
        null::numeric as amount,
        vp.days_vacant,
        null::text as request_title,
        '/properties?status=vacant&aging=14d'::text as link_path,
        20 as sort_order
      from vacant_properties vp
      where v_tenant_id is null
        and vp.days_vacant > 30
      order by vp.days_vacant desc, vp.address
      limit 4
    ) vacant_long_items

    union all

    select
      'overdue-' || op.id::text as item_key,
      'overdue_payment'::text as item_type,
      op.property_label,
      op.city,
      op.amount,
      null::int as days_vacant,
      null::text as request_title,
      '/finance?status=overdue'::text as link_path,
      30 as sort_order
    from overdue_payments op

    union all

    select
      'due-soon-' || dp.id::text as item_key,
      'due_soon_payment'::text as item_type,
      dp.property_label,
      dp.city,
      dp.amount,
      null::int as days_vacant,
      null::text as request_title,
      '/finance?status=due&range=7d'::text as link_path,
      40 as sort_order
    from due_soon_payments dp

    union all

    select
      'high-priority-' || r.id::text as item_key,
      'high_priority_request'::text as item_type,
      null::text as property_label,
      null::text as city,
      null::numeric as amount,
      null::int as days_vacant,
      coalesce(r.title, r.id::text) as request_title,
      '/maintenance-inbox?priority=high,critical'::text as link_path,
      50 as sort_order
    from high_priority_requests r
  )
  select
    i.item_key,
    i.item_type,
    i.property_label,
    i.city,
    i.amount,
    i.days_vacant,
    i.request_title,
    i.link_path,
    i.sort_order
  from items i
  order by i.sort_order, i.item_key
  limit (select max_items from cfg);
end;
$$;


ALTER FUNCTION public.portfolio_attention_items(p_account_id uuid, p_tenant_id uuid, p_limit integer) OWNER TO postgres;

--
-- Name: portfolio_health_snapshot(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.portfolio_health_snapshot(p_account_id uuid, p_tenant_id uuid DEFAULT NULL::uuid) RETURNS TABLE(property_count bigint, occupied_count bigint, vacant_count bigint, occupancy_rate integer, paid_amount numeric, due_amount numeric, overdue_amount numeric, due_soon_amount numeric, outstanding_amount numeric, overdue_0_7_amount numeric, overdue_8_30_amount numeric, overdue_30_plus_amount numeric, open_requests bigint, high_priority_open_requests bigint, waiting_over_48h bigint, active_work_orders bigint, work_orders_without_contractor bigint, contractor_ack_overdue bigint, stalled_repairs bigint, long_running_repairs bigint, repeat_repair_properties bigint, recent_open_created bigint, prev_open_created bigint, outstanding_current_month numeric, outstanding_previous_month numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  return query
  with tenant_scope as (
    select t.property_id
    from tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  scoped_properties as (
    select p.id
    from properties p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  occupied_properties as (
    select sp.id
    from scoped_properties sp
    where exists (
      select 1
      from tenants t
      where t.property_id = sp.id
    )
  ),
  scoped_payments as (
    select
      p.amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.due_date
    from payments p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
  ),
  scoped_requests as (
    select
      r.id,
      r.property_id,
      lower(coalesce(r.status, '')) as status_norm,
      lower(coalesce(r.priority, '')) as priority_norm,
      r.created_at
    from maintenance_requests r
    where r.account_id = p_account_id
      and (
        v_tenant_id is null
        or r.property_id = (select property_id from tenant_scope)
      )
  ),
  scoped_work_orders as (
    select
      w.property_id,
      lower(coalesce(w.status, '')) as status_norm,
      w.contractor_user_id,
      w.contractor_name,
      w.acknowledgement_due_at,
      w.acknowledged_at,
      lower(coalesce(w.acknowledgement_status, '')) as acknowledgement_status_norm,
      w.created_at,
      w.updated_at
    from work_orders w
    where w.account_id = p_account_id
      and (
        v_tenant_id is null
        or w.property_id = (select property_id from tenant_scope)
      )
  ),
  repeat_repair_properties as (
    select sr.property_id
    from scoped_requests sr
    where sr.property_id is not null
      and sr.created_at >= now() - interval '90 days'
    group by sr.property_id
    having count(*) >= 3
  ),
  finance as (
    select
      coalesce(sum(case when status_norm in ('paid', 'oplacone', 'opłacone') then amount else 0 end), 0) as paid_amount,
      coalesce(sum(case when status_norm in ('due', 'oczekujace', 'oczekujące', 'pending') then amount else 0 end), 0) as due_amount,
      coalesce(sum(case when status_norm in ('overdue', 'zalegle', 'zaległe') then amount else 0 end), 0) as overdue_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date >= current_date
             and due_date <= current_date + interval '7 days'
            then amount
            else 0
          end
        ),
        0
      ) as due_soon_amount,
      coalesce(sum(case when status_norm not in ('paid', 'oplacone', 'opłacone') then amount else 0 end), 0) as outstanding_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date <= current_date
             and current_date - due_date <= 7
            then amount
            else 0
          end
        ),
        0
      ) as overdue_0_7_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date <= current_date
             and current_date - due_date between 8 and 30
            then amount
            else 0
          end
        ),
        0
      ) as overdue_8_30_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and due_date <= current_date
             and current_date - due_date >= 31
            then amount
            else 0
          end
        ),
        0
      ) as overdue_30_plus_amount,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and date_trunc('month', due_date::timestamp) = date_trunc('month', current_date::timestamp)
            then amount
            else 0
          end
        ),
        0
      ) as outstanding_current_month,
      coalesce(
        sum(
          case
            when status_norm not in ('paid', 'oplacone', 'opłacone')
             and due_date is not null
             and date_trunc('month', due_date::timestamp) = date_trunc('month', current_date::timestamp - interval '1 month')
            then amount
            else 0
          end
        ),
        0
      ) as outstanding_previous_month
    from scoped_payments
  ),
  maintenance as (
    select
      (select count(*) from scoped_requests where status_norm not in ('closed', 'zamkniete', 'zamknięte')) as open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm not in ('closed', 'zamkniete', 'zamknięte')
          and priority_norm in ('high', 'critical', 'wysoki', 'krytyczny')
      ) as high_priority_open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm = 'waiting'
          and created_at <= now() - interval '48 hours'
      ) as waiting_over_48h,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked')
      ) as active_work_orders,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked')
          and contractor_user_id is null
      ) as work_orders_without_contractor,
      (
        select count(*)
        from scoped_work_orders
        where status_norm not in ('completed', 'cancelled', 'zakończone', 'anulowane')
          and (contractor_user_id is not null or nullif(coalesce(contractor_name, ''), '') is not null)
          and acknowledgement_due_at is not null
          and acknowledgement_due_at < now()
          and acknowledgement_status_norm <> 'acknowledged'
          and acknowledged_at is null
      ) as contractor_ack_overdue,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
          and coalesce(updated_at, created_at) <= now() - interval '72 hours'
      ) as stalled_repairs,
      (
        select count(*)
        from scoped_work_orders
        where status_norm not in ('completed', 'cancelled', 'zakończone', 'anulowane')
          and created_at <= now() - interval '14 days'
      ) as long_running_repairs,
      (select count(*) from repeat_repair_properties) as repeat_repair_properties,
      (
        select count(*)
        from scoped_requests
        where created_at >= now() - interval '7 days'
      ) as recent_open_created,
      (
        select count(*)
        from scoped_requests
        where created_at < now() - interval '7 days'
          and created_at >= now() - interval '14 days'
      ) as prev_open_created
  )
  select
    (select count(*) from scoped_properties) as property_count,
    (select count(*) from occupied_properties) as occupied_count,
    greatest((select count(*) from scoped_properties) - (select count(*) from occupied_properties), 0) as vacant_count,
    case
      when (select count(*) from scoped_properties) = 0 then 0
      else round(
        ((select count(*) from occupied_properties)::numeric / (select count(*) from scoped_properties)::numeric) * 100
      )::int
    end as occupancy_rate,
    finance.paid_amount,
    finance.due_amount,
    finance.overdue_amount,
    finance.due_soon_amount,
    finance.outstanding_amount,
    finance.overdue_0_7_amount,
    finance.overdue_8_30_amount,
    finance.overdue_30_plus_amount,
    maintenance.open_requests,
    maintenance.high_priority_open_requests,
    maintenance.waiting_over_48h,
    maintenance.active_work_orders,
    maintenance.work_orders_without_contractor,
    maintenance.contractor_ack_overdue,
    maintenance.stalled_repairs,
    maintenance.long_running_repairs,
    maintenance.repeat_repair_properties,
    maintenance.recent_open_created,
    maintenance.prev_open_created,
    finance.outstanding_current_month,
    finance.outstanding_previous_month
  from finance, maintenance;
end;
$$;


ALTER FUNCTION public.portfolio_health_snapshot(p_account_id uuid, p_tenant_id uuid) OWNER TO postgres;

--
-- Name: prevent_closing_if_work_order_open(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_closing_if_work_order_open() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  if new.status = 'zamkniete' then
    if exists (
      select 1
      from work_orders
      where maintenance_request_id = new.id
      and status != 'completed'
    ) then
      raise exception 'Cannot close request while work order is not completed';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.prevent_closing_if_work_order_open() OWNER TO postgres;

--
-- Name: prevent_closing_request_with_open_work_orders(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_closing_request_with_open_work_orders() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  if new.status = 'closed'
     and coalesce(old.status, '') is distinct from 'closed' then

    if exists (
      select 1
      from public.work_orders wo
      where wo.maintenance_request_id = new.id
        and coalesce(wo.status, '') not in ('completed', 'cancelled')
    ) then
      raise exception 'Cannot close maintenance request while linked work orders are not completed or cancelled.';
    end if;

  end if;

  return new;
end;
$$;


ALTER FUNCTION public.prevent_closing_request_with_open_work_orders() OWNER TO postgres;

--
-- Name: prevent_ledger_update_delete(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_ledger_update_delete() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  RAISE EXCEPTION
    'ledger_entries is append-only. Use reversal entries instead.';
END;
$$;


ALTER FUNCTION public.prevent_ledger_update_delete() OWNER TO postgres;

--
-- Name: preventive_maintenance_attention(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.preventive_maintenance_attention(p_account_id uuid, p_due_soon_days integer DEFAULT 14, p_limit integer DEFAULT 25) RETURNS TABLE(item_key text, item_type text, property_id uuid, property_label text, title text, category text, next_due_date date, days_until_due integer, assigned_to_label text, link_path text, sort_order integer)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with cfg as (
    select
      greatest(1, least(coalesce(p_due_soon_days, 14), 90)) as due_soon_days,
      greatest(1, least(coalesce(p_limit, 25), 200)) as max_items
  ),
  authz as (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  scoped_tasks as (
    select
      t.id,
      t.property_id,
      coalesce(p.address, '—') as property_label,
      t.title,
      t.category,
      t.next_due_date,
      (t.next_due_date - current_date)::int as days_until_due,
      coalesce(c.name, '') as assigned_to_label
    from public.preventive_maintenance_tasks t
    cross join authz a
    left join public.properties p on p.id = t.property_id
    left join public.contractors c on c.id = t.assigned_to_contractor_id
    where t.account_id = a.account_id
      and lower(coalesce(t.status, 'active')) = 'active'
  ),
  items as (
    select
      'preventive-overdue-' || st.id::text as item_key,
      'preventive_task_overdue'::text as item_type,
      st.property_id,
      st.property_label,
      st.title,
      st.category,
      st.next_due_date,
      st.days_until_due,
      st.assigned_to_label,
      ('/properties/' || st.property_id::text)::text as link_path,
      20 as sort_order
    from scoped_tasks st
    where st.next_due_date < current_date

    union all

    select
      'preventive-due-soon-' || st.id::text,
      'preventive_task_due_soon'::text,
      st.property_id,
      st.property_label,
      st.title,
      st.category,
      st.next_due_date,
      st.days_until_due,
      st.assigned_to_label,
      ('/properties/' || st.property_id::text)::text,
      40 as sort_order
    from scoped_tasks st, cfg
    where st.next_due_date >= current_date
      and st.next_due_date <= current_date + (cfg.due_soon_days || ' days')::interval
  )
  select
    i.item_key,
    i.item_type,
    i.property_id,
    i.property_label,
    i.title,
    i.category,
    i.next_due_date,
    i.days_until_due,
    i.assigned_to_label,
    i.link_path,
    i.sort_order
  from items i
  order by i.sort_order, i.next_due_date asc nulls last, i.title, i.item_key
  limit (select max_items from cfg);
$$;


ALTER FUNCTION public.preventive_maintenance_attention(p_account_id uuid, p_due_soon_days integer, p_limit integer) OWNER TO postgres;

--
-- Name: preventive_maintenance_next_due_date(text, integer, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.preventive_maintenance_next_due_date(p_frequency text, p_frequency_interval_days integer, p_completed_at date) RETURNS date
    LANGUAGE sql IMMUTABLE
    AS $$
  select
    case lower(coalesce(p_frequency, 'quarterly'))
      when 'monthly' then (p_completed_at + interval '1 month')::date
      when 'quarterly' then (p_completed_at + interval '3 months')::date
      when 'yearly' then (p_completed_at + interval '1 year')::date
      when 'custom' then (p_completed_at + (greatest(coalesce(p_frequency_interval_days, 1), 1) || ' days')::interval)::date
      else (p_completed_at + interval '3 months')::date
    end
$$;


ALTER FUNCTION public.preventive_maintenance_next_due_date(p_frequency text, p_frequency_interval_days integer, p_completed_at date) OWNER TO postgres;

--
-- Name: property_operational_health_snapshot(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.property_operational_health_snapshot(p_account_id uuid, p_property_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 200) RETURNS TABLE(property_id uuid, property_label text, score integer, category text, reasons jsonb, overdue_rent_amount numeric, open_request_count bigint, active_work_order_count bigint, stalled_repair_count bigint, ack_overdue_count bigint, long_running_repair_count bigint, requests_90_count bigint, overdue_preventive_count bigint, due_soon_preventive_count bigint, overdue_compliance_count bigint, due_soon_compliance_count bigint, missing_compliance_count bigint, expired_lease_count bigint, expiring_lease_count bigint, renewal_in_progress_count bigint, recent_operating_expenses numeric, recent_maintenance_cost numeric, tenant_count bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with recommended_compliance(category) as (
    values
      ('gas_safety'::text),
      ('epc_expiry'::text),
      ('insurance_renewal'::text),
      ('electrical_inspection'::text),
      ('fire_alarm_inspection'::text),
      ('smoke_alarm_check'::text),
      ('landlord_licensing'::text)
  ),
  scoped_properties as (
    select
      p.id,
      coalesce(p.address, '') as property_label,
      coalesce(p.rent, 0)::numeric as monthly_rent
    from public.properties p
    where p.account_id = p_account_id
      and (p_property_id is null or p.id = p_property_id)
    order by p.address asc
    limit greatest(coalesce(p_limit, 200), 1)
  ),
  payment_signals as (
    select
      sp.id as property_id,
      coalesce(sum(
        case
          when pay.paid_at is null
           and (
             lower(coalesce(pay.status, '')) in ('overdue', 'zaległe', 'zalegle')
             or (pay.due_date is not null and pay.due_date < current_date)
           )
          then coalesce(pay.amount, 0)
          else 0
        end
      ), 0)::numeric as overdue_rent_amount
    from scoped_properties sp
    left join public.payments pay
      on pay.account_id = p_account_id
     and pay.property_id = sp.id
    group by sp.id
  ),
  request_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(r.status, '')) not in ('closed', 'zamkniete', 'zamknięte')
      )::bigint as open_request_count,
      count(*) filter (
        where r.created_at >= now() - interval '90 days'
      )::bigint as requests_90_count
    from scoped_properties sp
    left join public.maintenance_requests r
      on r.account_id = p_account_id
     and r.property_id = sp.id
    group by sp.id
  ),
  work_order_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(w.status, '')) not in ('completed', 'cancelled', 'closed', 'zakończone', 'zakonczone', 'anulowane')
      )::bigint as active_work_order_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
          and coalesce(w.updated_at, w.created_at) <= now() - interval '5 days'
      )::bigint as stalled_repair_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) not in ('completed', 'cancelled', 'closed', 'zakończone', 'zakonczone', 'anulowane')
          and coalesce(lower(w.acknowledgement_status), 'pending') not in ('acknowledged', 'not_required')
          and w.acknowledgement_due_at is not null
          and w.acknowledgement_due_at < now()
      )::bigint as ack_overdue_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) not in ('completed', 'cancelled', 'closed', 'zakończone', 'zakonczone', 'anulowane')
          and w.created_at <= now() - interval '14 days'
      )::bigint as long_running_repair_count,
      coalesce(sum(
        case
          when coalesce(w.updated_at, w.created_at) >= now() - interval '90 days'
          then coalesce(w.invoice_amount, 0)
          else 0
        end
      ), 0)::numeric as recent_maintenance_cost
    from scoped_properties sp
    left join public.work_orders w
      on w.account_id = p_account_id
     and w.property_id = sp.id
    group by sp.id
  ),
  preventive_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(t.status, '')) = 'active'
          and t.next_due_date < current_date
      )::bigint as overdue_preventive_count,
      count(*) filter (
        where lower(coalesce(t.status, '')) = 'active'
          and t.next_due_date >= current_date
          and t.next_due_date <= current_date + 14
      )::bigint as due_soon_preventive_count
    from scoped_properties sp
    left join public.preventive_maintenance_tasks t
      on t.account_id = p_account_id
     and t.property_id = sp.id
    group by sp.id
  ),
  compliance_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(c.status, '')) not in ('completed', 'cancelled')
          and c.due_date < current_date
      )::bigint as overdue_compliance_count,
      count(*) filter (
        where lower(coalesce(c.status, '')) not in ('completed', 'cancelled')
          and c.due_date >= current_date
          and c.due_date <= current_date + greatest(coalesce(c.reminder_window_days, 30), 0)
      )::bigint as due_soon_compliance_count
    from scoped_properties sp
    left join public.compliance_items c
      on c.account_id = p_account_id
     and c.property_id = sp.id
    group by sp.id
  ),
  missing_compliance_signals as (
    select
      sp.id as property_id,
      case
        when count(ci.id) filter (
          where lower(coalesce(ci.status, '')) not in ('completed', 'cancelled')
        ) = 0 then 1::bigint
        else greatest(
          count(rc.category)::bigint -
          count(distinct case
            when lower(coalesce(ci.status, '')) not in ('completed', 'cancelled') then lower(coalesce(ci.category, ''))
            else null
          end)::bigint,
          0::bigint
        )
      end as missing_compliance_count
    from scoped_properties sp
    cross join recommended_compliance rc
    left join public.compliance_items ci
      on ci.account_id = p_account_id
     and ci.property_id = sp.id
    group by sp.id
  ),
  lease_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where (
          lower(coalesce(l.renewal_status, '')) = 'ended'
          or l.lease_end_date < current_date
        )
        and lower(coalesce(l.renewal_status, '')) <> 'renewed'
      )::bigint as expired_lease_count,
      count(*) filter (
        where lower(coalesce(l.renewal_status, '')) not in ('ended', 'renewed')
          and l.lease_end_date >= current_date
          and l.lease_end_date <= current_date + 60
      )::bigint as expiring_lease_count,
      count(*) filter (
        where lower(coalesce(l.renewal_status, '')) = 'renewal_in_progress'
      )::bigint as renewal_in_progress_count
    from scoped_properties sp
    left join public.leases l
      on l.account_id = p_account_id
     and l.property_id = sp.id
    group by sp.id
  ),
  tenant_signals as (
    select
      sp.id as property_id,
      count(t.id)::bigint as tenant_count
    from scoped_properties sp
    left join public.tenants t
      on t.account_id = p_account_id
     and t.property_id = sp.id
    group by sp.id
  ),
  expense_signals as (
    select
      sp.id as property_id,
      coalesce(sum(
        case
          when e.expense_date >= current_date - 90 then coalesce(e.amount, 0)
          else 0
        end
      ), 0)::numeric as recent_operating_expenses
    from scoped_properties sp
    left join public.property_operating_expenses e
      on e.account_id = p_account_id
     and e.property_id = sp.id
    group by sp.id
  ),
  assembled as (
    select
      sp.id as property_id,
      sp.property_label,
      sp.monthly_rent,
      coalesce(pay.overdue_rent_amount, 0)::numeric as overdue_rent_amount,
      coalesce(req.open_request_count, 0)::bigint as open_request_count,
      coalesce(wo.active_work_order_count, 0)::bigint as active_work_order_count,
      coalesce(wo.stalled_repair_count, 0)::bigint as stalled_repair_count,
      coalesce(wo.ack_overdue_count, 0)::bigint as ack_overdue_count,
      coalesce(wo.long_running_repair_count, 0)::bigint as long_running_repair_count,
      coalesce(req.requests_90_count, 0)::bigint as requests_90_count,
      coalesce(pm.overdue_preventive_count, 0)::bigint as overdue_preventive_count,
      coalesce(pm.due_soon_preventive_count, 0)::bigint as due_soon_preventive_count,
      coalesce(cs.overdue_compliance_count, 0)::bigint as overdue_compliance_count,
      coalesce(cs.due_soon_compliance_count, 0)::bigint as due_soon_compliance_count,
      coalesce(mc.missing_compliance_count, 0)::bigint as missing_compliance_count,
      coalesce(ls.expired_lease_count, 0)::bigint as expired_lease_count,
      coalesce(ls.expiring_lease_count, 0)::bigint as expiring_lease_count,
      coalesce(ls.renewal_in_progress_count, 0)::bigint as renewal_in_progress_count,
      coalesce(es.recent_operating_expenses, 0)::numeric as recent_operating_expenses,
      coalesce(wo.recent_maintenance_cost, 0)::numeric as recent_maintenance_cost,
      coalesce(ts.tenant_count, 0)::bigint as tenant_count
    from scoped_properties sp
    left join payment_signals pay on pay.property_id = sp.id
    left join request_signals req on req.property_id = sp.id
    left join work_order_signals wo on wo.property_id = sp.id
    left join preventive_signals pm on pm.property_id = sp.id
    left join compliance_signals cs on cs.property_id = sp.id
    left join missing_compliance_signals mc on mc.property_id = sp.id
    left join lease_signals ls on ls.property_id = sp.id
    left join tenant_signals ts on ts.property_id = sp.id
    left join expense_signals es on es.property_id = sp.id
  ),
  scored as (
    select
      a.*,
      greatest(
        0,
        100
        - (
          case
            when a.overdue_rent_amount > 0 and a.monthly_rent > 0 and a.overdue_rent_amount >= a.monthly_rent then 30
            when a.overdue_rent_amount > 0 then 22
            else 0
          end
          + case
              when (a.open_request_count + a.active_work_order_count) >= 4 then 10
              when (a.open_request_count + a.active_work_order_count) >= 2 then 6
              when (a.open_request_count + a.active_work_order_count) > 0 then 3
              else 0
            end
          + least(18, a.stalled_repair_count * 9)
          + least(16, a.ack_overdue_count * 8)
          + least(12, a.long_running_repair_count * 6)
          + case when a.requests_90_count >= 3 then 8 else 0 end
          + case
              when a.overdue_preventive_count > 0 then 8
              when a.due_soon_preventive_count > 0 then 3
              else 0
            end
          + case
              when a.overdue_compliance_count > 0 then 12
              when a.due_soon_compliance_count > 0 then 4
              else 0
            end
          + case when a.missing_compliance_count > 0 then 6 else 0 end
          + case
              when a.expired_lease_count > 0 then 15
              when a.expiring_lease_count > 0 then 6
              when a.renewal_in_progress_count > 0 then 4
              else 0
            end
          + case
              when a.monthly_rent > 0 and (a.recent_operating_expenses + a.recent_maintenance_cost) >= (a.monthly_rent * 2) then 6
              else 0
            end
          + case when a.tenant_count = 0 then 4 else 0 end
        )
      )::integer as score
    from assembled a
  )
  select
    s.property_id,
    s.property_label,
    s.score,
    case
      when s.score >= 85 then 'healthy'
      when s.score >= 60 then 'attention_needed'
      else 'high_risk'
    end as category,
    (
      select coalesce(jsonb_agg(reason order by (reason->>'penalty')::int desc), '[]'::jsonb)
      from (
        select jsonb_build_object('key', 'overdue_rent', 'penalty',
          case
            when s.overdue_rent_amount > 0 and s.monthly_rent > 0 and s.overdue_rent_amount >= s.monthly_rent then 30
            else 22
          end,
          'amount', s.overdue_rent_amount
        ) as reason
        where s.overdue_rent_amount > 0

        union all
        select jsonb_build_object('key', 'maintenance_pressure', 'penalty',
          case
            when (s.open_request_count + s.active_work_order_count) >= 4 then 10
            when (s.open_request_count + s.active_work_order_count) >= 2 then 6
            else 3
          end,
          'count', (s.open_request_count + s.active_work_order_count)
        )
        where (s.open_request_count + s.active_work_order_count) > 0

        union all
        select jsonb_build_object('key', 'stalled_repairs', 'penalty', least(18, s.stalled_repair_count * 9), 'count', s.stalled_repair_count)
        where s.stalled_repair_count > 0

        union all
        select jsonb_build_object('key', 'contractor_ack_overdue', 'penalty', least(16, s.ack_overdue_count * 8), 'count', s.ack_overdue_count)
        where s.ack_overdue_count > 0

        union all
        select jsonb_build_object('key', 'long_running_repairs', 'penalty', least(12, s.long_running_repair_count * 6), 'count', s.long_running_repair_count)
        where s.long_running_repair_count > 0

        union all
        select jsonb_build_object('key', 'repeat_repairs', 'penalty', 8, 'count', s.requests_90_count)
        where s.requests_90_count >= 3

        union all
        select jsonb_build_object('key', 'preventive_overdue', 'penalty', 8, 'count', s.overdue_preventive_count)
        where s.overdue_preventive_count > 0

        union all
        select jsonb_build_object('key', 'preventive_due_soon', 'penalty', 3, 'count', s.due_soon_preventive_count)
        where s.overdue_preventive_count = 0 and s.due_soon_preventive_count > 0

        union all
        select jsonb_build_object('key', 'compliance_overdue', 'penalty', 12, 'count', s.overdue_compliance_count)
        where s.overdue_compliance_count > 0

        union all
        select jsonb_build_object('key', 'compliance_due_soon', 'penalty', 4, 'count', s.due_soon_compliance_count)
        where s.overdue_compliance_count = 0 and s.due_soon_compliance_count > 0

        union all
        select jsonb_build_object('key', 'compliance_missing_setup', 'penalty', 6, 'count', s.missing_compliance_count)
        where s.missing_compliance_count > 0

        union all
        select jsonb_build_object('key', 'lease_expired', 'penalty', 15)
        where s.expired_lease_count > 0

        union all
        select jsonb_build_object('key', 'lease_expiring', 'penalty', 6)
        where s.expired_lease_count = 0 and s.expiring_lease_count > 0

        union all
        select jsonb_build_object('key', 'lease_renewal_in_progress', 'penalty', 4)
        where s.expired_lease_count = 0 and s.expiring_lease_count = 0 and s.renewal_in_progress_count > 0

        union all
        select jsonb_build_object('key', 'operating_cost_pressure', 'penalty', 6, 'amount', (s.recent_operating_expenses + s.recent_maintenance_cost))
        where s.monthly_rent > 0 and (s.recent_operating_expenses + s.recent_maintenance_cost) >= (s.monthly_rent * 2)

        union all
        select jsonb_build_object('key', 'vacant_property', 'penalty', 4)
        where s.tenant_count = 0
      ) reasons(reason)
    ) as reasons,
    s.overdue_rent_amount,
    s.open_request_count,
    s.active_work_order_count,
    s.stalled_repair_count,
    s.ack_overdue_count,
    s.long_running_repair_count,
    s.requests_90_count,
    s.overdue_preventive_count,
    s.due_soon_preventive_count,
    s.overdue_compliance_count,
    s.due_soon_compliance_count,
    s.missing_compliance_count,
    s.expired_lease_count,
    s.expiring_lease_count,
    s.renewal_in_progress_count,
    s.recent_operating_expenses,
    s.recent_maintenance_cost,
    s.tenant_count
  from scored s
  order by s.score asc, s.property_label asc;
$$;


