--
-- Name: rls_auto_enable(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rls_auto_enable() RETURNS event_trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog'
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION public.rls_auto_enable() OWNER TO postgres;

--
-- Name: root_delete_account(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.root_delete_account(p_root_account_id uuid, p_target_account_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  if p_target_account_id is null then
    raise exception 'Missing target account';
  end if;

  select lower(am.role::text)
  into v_member_role
  from public.account_members am
  where am.account_id = p_root_account_id
    and am.user_id = v_uid
  limit 1;

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  if p_target_account_id = p_root_account_id then
    raise exception 'Cannot delete root account';
  end if;

  delete from public.accounts a
  where a.id = p_target_account_id;

  if not found then
    raise exception 'Target account not found';
  end if;

  perform public.log_security_event(
    p_root_account_id,
    'account_deleted',
    'account',
    p_target_account_id,
    jsonb_build_object(
      'target_account_id', p_target_account_id,
      'root_account_id', p_root_account_id
    )
  );

  return jsonb_build_object(
    'ok', true,
    'account_id', p_target_account_id
  );
exception
  when foreign_key_violation then
    raise exception 'Cannot delete account with related data; disable it instead';
end;
$$;


ALTER FUNCTION public.root_delete_account(p_root_account_id uuid, p_target_account_id uuid) OWNER TO postgres;

--
-- Name: root_list_accounts(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.root_list_accounts(p_root_account_id uuid) RETURNS TABLE(id uuid, name text, is_root boolean, is_disabled boolean, disabled_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
  v_previous_disabled boolean;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select lower(am.role::text)
  into v_member_role
  from public.account_members am
  where am.account_id = p_root_account_id
    and am.user_id = v_uid
  limit 1;

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  return query
  select
    a.id,
    a.name,
    coalesce(a.is_root, false) as is_root,
    coalesce(a.is_disabled, false) as is_disabled,
    a.disabled_at,
    a.created_at
  from public.accounts a
  order by a.created_at desc nulls last, a.id;
end;
$$;


ALTER FUNCTION public.root_list_accounts(p_root_account_id uuid) OWNER TO postgres;

--
-- Name: root_set_account_disabled(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.root_set_account_disabled(p_root_account_id uuid, p_target_account_id uuid, p_disabled boolean) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
  v_previous_disabled boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  if p_target_account_id is null then
    raise exception 'Missing target account';
  end if;

  select lower(am.role::text)
  into v_member_role
  from public.account_members am
  where am.account_id = p_root_account_id
    and am.user_id = v_uid
  limit 1;

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  if p_target_account_id = p_root_account_id then
    raise exception 'Cannot disable root account';
  end if;

  select coalesce(a.is_disabled, false)
  into v_previous_disabled
  from public.accounts a
  where a.id = p_target_account_id
  limit 1;

  update public.accounts a
  set
    is_disabled = coalesce(p_disabled, false),
    disabled_at = case when coalesce(p_disabled, false) then now() else null end
  where a.id = p_target_account_id;

  if not found then
    raise exception 'Target account not found';
  end if;

  if coalesce(v_previous_disabled, false) is distinct from coalesce(p_disabled, false) then
    perform public.log_security_event(
      p_target_account_id,
      case when coalesce(p_disabled, false) then 'account_disabled' else 'account_enabled' end,
      'account',
      p_target_account_id,
      jsonb_build_object(
        'target_account_id', p_target_account_id,
        'root_account_id', p_root_account_id,
        'old_is_disabled', coalesce(v_previous_disabled, false),
        'new_is_disabled', coalesce(p_disabled, false)
      )
    );
  end if;

  return jsonb_build_object(
    'ok', true,
    'account_id', p_target_account_id,
    'is_disabled', coalesce(p_disabled, false)
  );
end;
$$;


ALTER FUNCTION public.root_set_account_disabled(p_root_account_id uuid, p_target_account_id uuid, p_disabled boolean) OWNER TO postgres;

--
-- Name: safe_uuid(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.safe_uuid(p text) RETURNS uuid
    LANGUAGE plpgsql IMMUTABLE
    AS $_$
begin
  if p is null then
    return null;
  end if;

  if p ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then
    return p::uuid;
  end if;

  return null;
exception when others then
  return null;
end;
$_$;


ALTER FUNCTION public.safe_uuid(p text) OWNER TO postgres;

--
-- Name: security_anomaly_alerts; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.security_anomaly_alerts (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    alert_type text NOT NULL,
    severity text DEFAULT 'action'::text NOT NULL,
    status text DEFAULT 'open'::text NOT NULL,
    actor_user_id uuid,
    entity_type text,
    entity_id uuid,
    title text NOT NULL,
    summary text NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    dedupe_key text NOT NULL,
    alert_count integer DEFAULT 1 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    last_seen_at timestamp with time zone DEFAULT now() NOT NULL,
    acknowledged_at timestamp with time zone,
    resolved_at timestamp with time zone,
    classification text,
    classified_by_user_id uuid,
    classified_at timestamp with time zone,
    assigned_to_user_id uuid,
    assigned_by_user_id uuid,
    assigned_at timestamp with time zone,
    acknowledged_by_user_id uuid,
    resolved_by_user_id uuid,
    resolution_note text,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT security_anomaly_alerts_alert_count_check CHECK ((alert_count >= 1)),
    CONSTRAINT security_anomaly_alerts_classification_check CHECK (((classification IS NULL) OR (lower(classification) = ANY (ARRAY['suspicious'::text, 'expected'::text, 'false_positive'::text, 'informational'::text])))),
    CONSTRAINT security_anomaly_alerts_severity_check CHECK ((lower(severity) = ANY (ARRAY['info'::text, 'action'::text, 'urgent'::text]))),
    CONSTRAINT security_anomaly_alerts_status_check CHECK ((lower(status) = ANY (ARRAY['open'::text, 'acknowledged'::text, 'resolved'::text])))
);


ALTER TABLE public.security_anomaly_alerts OWNER TO postgres;

--
-- Name: TABLE security_anomaly_alerts; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.security_anomaly_alerts IS 'Open internal security anomaly alerts derived from security_audit_ledger patterns.';


--
-- Name: COLUMN security_anomaly_alerts.metadata; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.security_anomaly_alerts.metadata IS 'Compact anomaly payload with thresholds, detection window, count details, and review filter hints.';


--
-- Name: COLUMN security_anomaly_alerts.classification; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.security_anomaly_alerts.classification IS 'Analyst classification for the current alert lifecycle.';


--
-- Name: COLUMN security_anomaly_alerts.resolution_note; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.security_anomaly_alerts.resolution_note IS 'Optional analyst note captured at resolution time.';


--
-- Name: security_anomaly_alert_apply(uuid, text, text, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.security_anomaly_alert_apply(p_alert_id uuid, p_operation text, p_classification text DEFAULT NULL::text, p_assigned_to_user_id uuid DEFAULT NULL::uuid, p_resolution_note text DEFAULT NULL::text) RETURNS public.security_anomaly_alerts
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_actor_user_id uuid := auth.uid();
  v_operation text := lower(trim(coalesce(p_operation, '')));
  v_classification text := nullif(lower(trim(coalesce(p_classification, ''))), '');
  v_resolution_note text := nullif(trim(coalesce(p_resolution_note, '')), '');
  v_alert public.security_anomaly_alerts;
  v_updated public.security_anomaly_alerts;
  v_assignee_role text;
begin
  if v_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  if p_alert_id is null then
    raise exception 'Missing alert id';
  end if;

  if v_operation not in ('acknowledge', 'classify', 'assign', 'resolve') then
    raise exception 'Unsupported operation';
  end if;

  select *
  into v_alert
  from public.security_anomaly_alerts
  where id = p_alert_id
  for update;

  if v_alert.id is null then
    raise exception 'Alert not found';
  end if;

  perform public.assert_manage_account_access(v_alert.account_id);

  if v_operation = 'acknowledge' then
    if lower(v_alert.status) <> 'open' then
      raise exception 'Only open alerts can be acknowledged';
    end if;

    update public.security_anomaly_alerts
    set
      status = 'acknowledged',
      acknowledged_by_user_id = v_actor_user_id,
      acknowledged_at = now()
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_acknowledged',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_status', v_alert.status,
        'new_status', v_updated.status
      )
    );
  elsif v_operation = 'classify' then
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Resolved alerts cannot be reclassified';
    end if;

    if v_classification is null or v_classification not in ('suspicious', 'expected', 'false_positive', 'informational') then
      raise exception 'Invalid classification';
    end if;

    update public.security_anomaly_alerts
    set
      classification = v_classification,
      classified_by_user_id = v_actor_user_id,
      classified_at = now()
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_classified',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_classification', v_alert.classification,
        'new_classification', v_updated.classification
      )
    );
  elsif v_operation = 'assign' then
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Resolved alerts cannot be reassigned';
    end if;

    if p_assigned_to_user_id is not null then
      select lower(am.role::text)
      into v_assignee_role
      from public.account_members am
      where am.account_id = v_alert.account_id
        and am.user_id = p_assigned_to_user_id
      limit 1;

      if v_assignee_role is null or v_assignee_role not in ('owner', 'admin', 'staff') then
        raise exception 'Assignee must be a privileged account member';
      end if;
    end if;

    update public.security_anomaly_alerts
    set
      assigned_to_user_id = p_assigned_to_user_id,
      assigned_by_user_id = case when p_assigned_to_user_id is null then null else v_actor_user_id end,
      assigned_at = case when p_assigned_to_user_id is null then null else now() end
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_assigned',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_assigned_to_user_id', v_alert.assigned_to_user_id,
        'new_assigned_to_user_id', v_updated.assigned_to_user_id
      )
    );
  else
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Alert is already resolved';
    end if;

    update public.security_anomaly_alerts
    set
      status = 'resolved',
      resolved_by_user_id = v_actor_user_id,
      resolved_at = now(),
      resolution_note = v_resolution_note
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_resolved',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_status', v_alert.status,
        'new_status', v_updated.status,
        'resolution_note', coalesce(v_updated.resolution_note, '')
      )
    );
  end if;

  return v_updated;
end;
$$;


ALTER FUNCTION public.security_anomaly_alert_apply(p_alert_id uuid, p_operation text, p_classification text, p_assigned_to_user_id uuid, p_resolution_note text) OWNER TO postgres;

--
-- Name: FUNCTION security_anomaly_alert_apply(p_alert_id uuid, p_operation text, p_classification text, p_assigned_to_user_id uuid, p_resolution_note text); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.security_anomaly_alert_apply(p_alert_id uuid, p_operation text, p_classification text, p_assigned_to_user_id uuid, p_resolution_note text) IS 'Applies a privileged analyst lifecycle action to a security anomaly alert and records the action in security_audit_ledger.';


--
-- Name: security_audit_detect_anomalies(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.security_audit_detect_anomalies() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_target_user_id uuid := nullif(coalesce(new.metadata->>'target_user_id', ''), '')::uuid;
  v_role_change_target_count integer := 0;
  v_role_change_account_count integer := 0;
  v_doc_delete_actor_count integer := 0;
  v_doc_delete_account_count integer := 0;
  v_actor_member_role text := null;
  v_actor_is_tenant boolean := false;
  v_actor_is_contractor boolean := false;
  v_role_change_target_threshold integer := 3;
  v_role_change_account_threshold integer := 5;
  v_role_change_window_minutes integer := 30;
  v_document_delete_actor_threshold integer := 5;
  v_document_delete_account_threshold integer := 10;
  v_document_delete_window_minutes integer := 15;
begin
  if new.account_id is null then
    return new;
  end if;

  select
    coalesce(s.role_change_target_threshold, 3),
    coalesce(s.role_change_account_threshold, 5),
    coalesce(s.role_change_window_minutes, 30),
    coalesce(s.document_delete_actor_threshold, 5),
    coalesce(s.document_delete_account_threshold, 10),
    coalesce(s.document_delete_window_minutes, 15)
  into
    v_role_change_target_threshold,
    v_role_change_account_threshold,
    v_role_change_window_minutes,
    v_document_delete_actor_threshold,
    v_document_delete_account_threshold,
    v_document_delete_window_minutes
  from public.account_security_settings s
  where s.account_id = new.account_id
  limit 1;

  if not found then
    v_role_change_target_threshold := 3;
    v_role_change_account_threshold := 5;
    v_role_change_window_minutes := 30;
    v_document_delete_actor_threshold := 5;
    v_document_delete_account_threshold := 10;
    v_document_delete_window_minutes := 15;
  end if;

  if new.action = 'role_changed' then
    if coalesce(new.metadata->>'change_source', '') = 'invite_acceptance' then
      return new;
    end if;

    if v_target_user_id is not null then
      select count(*)
      into v_role_change_target_count
      from public.security_audit_ledger sal
      where sal.account_id = new.account_id
        and sal.action = 'role_changed'
        and coalesce(sal.metadata->>'change_source', '') <> 'invite_acceptance'
        and coalesce(sal.metadata->>'target_user_id', '') = v_target_user_id::text
        and sal.created_at >= now() - make_interval(mins => v_role_change_window_minutes);
    end if;

    select count(*)
    into v_role_change_account_count
    from public.security_audit_ledger sal
    where sal.account_id = new.account_id
      and sal.action = 'role_changed'
      and coalesce(sal.metadata->>'change_source', '') <> 'invite_acceptance'
      and sal.created_at >= now() - make_interval(mins => v_role_change_window_minutes);

    if v_role_change_target_count >= v_role_change_target_threshold then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'repeated_role_changes',
        'action',
        'Repeated role changes detected',
        'Multiple role changes were recorded for the same account member within the configured review window.',
        new.actor_user_id,
        'account_member',
        v_target_user_id,
        'repeated_role_changes:target:' || v_target_user_id::text,
        jsonb_build_object(
          'detection_window_minutes', v_role_change_window_minutes,
          'threshold', v_role_change_target_threshold,
          'event_count', v_role_change_target_count,
          'target_user_id', v_target_user_id,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'role_changed',
            'actorUserId', coalesce(new.actor_user_id::text, ''),
            'entityType', 'account_member',
            'entityId', v_target_user_id::text
          )
        )
      );
    elsif v_role_change_account_count >= v_role_change_account_threshold then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'repeated_role_changes',
        'action',
        'High volume of role changes detected',
        'Multiple role changes were recorded across the account within the configured review window.',
        new.actor_user_id,
        'account',
        new.account_id,
        'repeated_role_changes:account',
        jsonb_build_object(
          'detection_window_minutes', v_role_change_window_minutes,
          'threshold', v_role_change_account_threshold,
          'event_count', v_role_change_account_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'role_changed'
          )
        )
      );
    end if;
  elsif new.action = 'document_deleted' then
    if new.actor_user_id is not null then
      select count(*)
      into v_doc_delete_actor_count
      from public.security_audit_ledger sal
      where sal.account_id = new.account_id
        and sal.action = 'document_deleted'
        and sal.actor_user_id = new.actor_user_id
        and sal.created_at >= now() - make_interval(mins => v_document_delete_window_minutes);
    end if;

    select count(*)
    into v_doc_delete_account_count
    from public.security_audit_ledger sal
    where sal.account_id = new.account_id
      and sal.action = 'document_deleted'
      and sal.created_at >= now() - make_interval(mins => v_document_delete_window_minutes);

    if v_doc_delete_actor_count >= v_document_delete_actor_threshold and new.actor_user_id is not null then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'document_deletion_burst',
        'urgent',
        'Document deletion burst detected',
        'A single actor deleted multiple documents in a short time window.',
        new.actor_user_id,
        'document',
        new.entity_id,
        'document_deletion_burst:actor:' || new.actor_user_id::text,
        jsonb_build_object(
          'detection_window_minutes', v_document_delete_window_minutes,
          'threshold', v_document_delete_actor_threshold,
          'event_count', v_doc_delete_actor_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'document_deleted',
            'actorUserId', new.actor_user_id::text,
            'entityType', 'document'
          )
        )
      );
    elsif v_doc_delete_account_count >= v_document_delete_account_threshold then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'document_deletion_burst',
        'urgent',
        'Account-level document deletion burst detected',
        'Document deletions spiked across the account in a short time window.',
        new.actor_user_id,
        'account',
        new.account_id,
        'document_deletion_burst:account',
        jsonb_build_object(
          'detection_window_minutes', v_document_delete_window_minutes,
          'threshold', v_document_delete_account_threshold,
          'event_count', v_doc_delete_account_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'document_deleted'
          )
        )
      );
    end if;
  elsif new.action in (
    'role_changed',
    'account_disabled',
    'account_enabled',
    'account_deleted',
    'account_invitation_created',
    'landlord_invitation_created'
  ) then
    select lower(am.role::text)
    into v_actor_member_role
    from public.account_members am
    where am.account_id = new.account_id
      and am.user_id = new.actor_user_id
    limit 1;

    select exists (
      select 1
      from public.tenants t
      where t.account_id = new.account_id
        and t.user_id = new.actor_user_id
    )
    into v_actor_is_tenant;

    select exists (
      select 1
      from public.contractors c
      where c.account_id = new.account_id
        and c.user_id = new.actor_user_id
    )
    into v_actor_is_contractor;

    if v_actor_member_role = 'staff' or v_actor_is_tenant or v_actor_is_contractor then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'cross_role_admin_activity',
        case when v_actor_is_tenant or v_actor_is_contractor then 'urgent' else 'action' end,
        'Admin/security action crossed role boundary',
        'A privileged administrative action should be reviewed because the actor role or account position is unusual for this type of change.',
        new.actor_user_id,
        coalesce(new.entity_type, 'account'),
        new.entity_id,
        'cross_role_admin_activity:' || coalesce(new.actor_user_id::text, 'system') || ':' || new.action,
        jsonb_build_object(
          'actor_member_role', coalesce(v_actor_member_role, ''),
          'actor_is_tenant', v_actor_is_tenant,
          'actor_is_contractor', v_actor_is_contractor,
          'trigger_action', new.action,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', new.action,
            'actorUserId', coalesce(new.actor_user_id::text, ''),
            'entityType', coalesce(new.entity_type, '')
          )
        )
      );
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.security_audit_detect_anomalies() OWNER TO postgres;

--
-- Name: FUNCTION security_audit_detect_anomalies(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.security_audit_detect_anomalies() IS 'Lightweight trigger-based anomaly detection for repeated role changes, document deletion bursts, and cross-role administrative activity.';


