    AS $$
begin
  raise exception 'security_audit_ledger is append-only';
end;
$$;


ALTER FUNCTION public.security_audit_ledger_block_mutation() OWNER TO postgres;

--
-- Name: security_audit_log_account_invitation_create(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.security_audit_log_account_invitation_create() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
declare
  v_action text := case
    when lower(coalesce(new.role::text, '')) = 'owner' then 'landlord_invitation_created'
    else 'account_invitation_created'
  end;
begin
  if new.accepted_at is not null or new.revoked_at is not null then
    return new;
  end if;

  perform public.log_security_event(
    new.account_id,
    v_action,
    'account_invitation',
    new.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'invite_id', new.id,
        'email', lower(coalesce(new.email, '')),
        'invited_role', lower(coalesce(new.role::text, '')),
        'invited_by', new.invited_by,
        'account_id', new.account_id
      )
    )
  );

  return new;
end;
$$;


ALTER FUNCTION public.security_audit_log_account_invitation_create() OWNER TO postgres;

--
-- Name: security_audit_log_document_delete(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.security_audit_log_document_delete() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
declare
  v_doc jsonb := to_jsonb(old);
begin
  perform public.log_security_event(
    (v_doc->>'account_id')::uuid,
    'document_deleted',
    'document',
    old.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'document_id', old.id,
        'storage_path', v_doc->>'storage_path',
        'property_id', v_doc->>'property_id',
        'tenant_id', v_doc->>'tenant_id',
        'scope', v_doc->>'scope',
        'visibility', v_doc->>'visibility',
        'deletion_source', 'documents_delete'
      )
    )
  );

  return old;
end;
$$;


ALTER FUNCTION public.security_audit_log_document_delete() OWNER TO postgres;

--
-- Name: security_audit_log_work_order_assignment(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.security_audit_log_work_order_assignment() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
declare
  v_had_contractor boolean := false;
  v_has_contractor boolean := false;
begin
  if tg_op = 'INSERT' then
    v_has_contractor := new.contractor_user_id is not null or nullif(coalesce(new.contractor_name, ''), '') is not null;
    if not v_has_contractor then
      return new;
    end if;
  else
    v_had_contractor := old.contractor_user_id is not null or nullif(coalesce(old.contractor_name, ''), '') is not null;
    v_has_contractor := new.contractor_user_id is not null or nullif(coalesce(new.contractor_name, ''), '') is not null;

    if not v_has_contractor then
      return new;
    end if;

    if not (
      old.contractor_user_id is distinct from new.contractor_user_id
      or coalesce(old.contractor_name, '') is distinct from coalesce(new.contractor_name, '')
    ) then
      return new;
    end if;
  end if;

  perform public.log_security_event(
    new.account_id,
    'contractor_assigned',
    'work_order',
    new.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'work_order_id', new.id,
        'maintenance_request_id', new.maintenance_request_id,
        'property_id', new.property_id,
        'previous_contractor_user_id', case when tg_op = 'UPDATE' then old.contractor_user_id else null end,
        'previous_contractor_name', case when tg_op = 'UPDATE' then nullif(coalesce(old.contractor_name, ''), '') else null end,
        'contractor_user_id', new.contractor_user_id,
        'contractor_name', nullif(coalesce(new.contractor_name, ''), ''),
        'assignment_source', case when tg_op = 'INSERT' and not v_had_contractor then 'work_order_create' else 'work_order_update' end
      )
    )
  );

  return new;
end;
$$;


ALTER FUNCTION public.security_audit_log_work_order_assignment() OWNER TO postgres;

--
-- Name: set_document_access(uuid, text, text, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.set_document_access(p_document_id uuid, p_scope text, p_visibility text, p_property_id uuid DEFAULT NULL::uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT auth.uid()) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  -- Validate enum-ish values (match your check constraints)
  if p_scope not in ('property','tenant','shared','account') then
    raise exception 'Invalid scope: %', p_scope;
  end if;

  if p_visibility not in ('owner_admin','staff','tenant','private') then
    raise exception 'Invalid visibility: %', p_visibility;
  end if;

  -- Enforce consistency by constructing IDs from scope
  update public.documents
  set
    scope = p_scope,
    visibility = p_visibility,
    property_id = case when p_scope in ('property','shared') then p_property_id else null end,
    tenant_id   = case when p_scope in ('tenant','shared') then p_tenant_id else null end,
    updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  return v_doc;
end;
$$;


ALTER FUNCTION public.set_document_access(p_document_id uuid, p_scope text, p_visibility text, p_property_id uuid, p_tenant_id uuid, p_actor_user_id uuid) OWNER TO postgres;

--
-- Name: set_document_tags(uuid, public.document_tag[], uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.set_document_tags(p_document_id uuid, p_tags public.document_tag[], p_actor_user_id uuid DEFAULT auth.uid()) RETURNS public.documents
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  update public.documents
  set tags = coalesce(p_tags, '{}'::public.document_tag[]),
      updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  -- Optional audit entry (uses allowed action values)
  insert into public.document_audit_log (
    document_id, action, performed_by, performed_at, account_id, created_at
  )
  values (
    v_doc.id, 'download', p_actor_user_id, now(), v_doc.account_id, now()
  );

  return v_doc;
end;
$$;


ALTER FUNCTION public.set_document_tags(p_document_id uuid, p_tags public.document_tag[], p_actor_user_id uuid) OWNER TO postgres;

