--
-- Name: should_send_notification(uuid, uuid, text, text, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.should_send_notification(p_account_id uuid, p_recipient_user_id uuid, p_type text, p_entity_type text, p_entity_id uuid, p_window_seconds integer DEFAULT 90) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $$
declare
  v_exists boolean;
begin
  select true
    into v_exists
  from public.notifications n
  where n.account_id = p_account_id
    and n.recipient_user_id = p_recipient_user_id
    and n.type = p_type
    and n.entity_type = p_entity_type
    and n.entity_id = p_entity_id
    and n.created_at >= now() - make_interval(secs => p_window_seconds)
  limit 1;

  return not coalesce(v_exists, false);
end;
$$;


ALTER FUNCTION public.should_send_notification(p_account_id uuid, p_recipient_user_id uuid, p_type text, p_entity_type text, p_entity_id uuid, p_window_seconds integer) OWNER TO postgres;

