-- Name: tg_prevent_blocked_work_orders(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_prevent_blocked_work_orders() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  if lower(coalesce(new.status,'')) = 'blocked' then
    raise exception 'blocked is deprecated and must not be used';
  end if;
  new.status := lower(coalesce(new.status,'assigned'));
  return new;
end;
$$;


