CREATE FUNCTION public.tg_sync_maintenance_from_work_orders() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_request_id uuid;
begin
  v_request_id := coalesce(new.maintenance_request_id, old.maintenance_request_id);

  if v_request_id is null then
    return coalesce(new, old);
  end if;

  perform public.sync_maintenance_request_from_work_orders(v_request_id);

  return coalesce(new, old);
end;
$$;


