--
-- Name: tg_sync_payments_to_ledger(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_sync_payments_to_ledger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  -- Safety
  if new.account_id is null then
    return new;
  end if;

  -- Only mirror to ledger when actually PAID
  if new.paid_at is not null and coalesce(new.status,'') <> 'void' then
    insert into public.ledger_entries (
      account_id, property_id, tenant_id,
      entry_type, direction, amount, currency,
      occurred_at, notes,
      source_table, source_id
    )
    values (
      new.account_id,
      new.property_id,
      new.tenant_id,
      'payment',
      'in',
      new.amount::numeric(12,2),
      'PLN',
      new.paid_at::timestamptz,
      ('payments status=' || coalesce(new.status,'unknown')
        || case when new.due_date is not null then ', due=' || new.due_date::text else '' end
        || case when new.paid_at is not null then ', paid=' || new.paid_at::text else '' end
      )::text,
      'payments',
      new.id
    )
    on conflict (source_table, source_id)
    do update set
      account_id  = excluded.account_id,
      property_id = excluded.property_id,
      tenant_id   = excluded.tenant_id,
      amount      = excluded.amount,
      occurred_at = excluded.occurred_at,
      notes       = excluded.notes,
      updated_at  = now();

  else
    -- If it is NOT paid (or is void), remove ledger row if present
    delete from public.ledger_entries
    where source_table = 'payments'
      and source_id = new.id;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.tg_sync_payments_to_ledger() OWNER TO postgres;

--
-- Name: tg_sync_work_order_expense_fact(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_sync_work_order_expense_fact() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  perform public.sync_work_order_expense_fact(coalesce(new.work_order_id, old.work_order_id));
  return coalesce(new, old);
end;
$$;


ALTER FUNCTION public.tg_sync_work_order_expense_fact() OWNER TO postgres;

--
-- Name: tg_work_order_ack_defaults(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_work_order_ack_defaults() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  has_contractor boolean;
  contractor_changed boolean;
begin
  has_contractor := new.contractor_user_id is not null or nullif(coalesce(new.contractor_name, ''), '') is not null;
  contractor_changed := tg_op = 'INSERT';
  if tg_op = 'UPDATE' then
    contractor_changed := contractor_changed
      or old.contractor_user_id is distinct from new.contractor_user_id
      or coalesce(old.contractor_name, '') is distinct from coalesce(new.contractor_name, '');
  end if;

  if not has_contractor then
    new.assigned_at := null;
    new.acknowledged_at := null;
    new.acknowledgement_due_at := null;
    new.acknowledgement_status := 'not_required';
    return new;
  end if;

  if contractor_changed then
    new.assigned_at := coalesce(new.assigned_at, now());
    if tg_op = 'UPDATE' and old.acknowledged_at is distinct from new.acknowledged_at then
      null;
    elsif tg_op = 'UPDATE' and (
      old.contractor_user_id is distinct from new.contractor_user_id
      or coalesce(old.contractor_name, '') is distinct from coalesce(new.contractor_name, '')
    ) then
      new.acknowledged_at := null;
      new.acknowledgement_status := 'pending';
      new.acknowledgement_due_at := now() + interval '48 hours';
    end if;
  end if;

  new.assigned_at := coalesce(new.assigned_at, now());
  new.acknowledgement_due_at := coalesce(new.acknowledgement_due_at, new.assigned_at + interval '48 hours');

  if new.acknowledged_at is not null then
    new.acknowledgement_status := 'acknowledged';
  else
    new.acknowledgement_status := coalesce(nullif(new.acknowledgement_status, ''), 'pending');
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.tg_work_order_ack_defaults() OWNER TO postgres;

--
-- Name: tg_work_orders_block_contractor_edits(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_work_orders_block_contractor_edits() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  is_staff boolean;
begin
  is_staff := public.account_role_for(NEW.account_id) = any (array['owner','admin','staff']);
  if is_staff then
    return NEW;
  end if;

  -- block protected fields for contractor updates
  if (NEW.account_id is distinct from OLD.account_id)
    or (NEW.property_id is distinct from OLD.property_id)
    or (NEW.maintenance_request_id is distinct from OLD.maintenance_request_id)
    or (NEW.contractor_user_id is distinct from OLD.contractor_user_id)
    or (NEW.contractor_name is distinct from OLD.contractor_name)
    or (NEW.contractor_phone is distinct from OLD.contractor_phone)
    or (NEW.quote_amount is distinct from OLD.quote_amount)
    or (NEW.created_by is distinct from OLD.created_by)
    or (NEW.created_at is distinct from OLD.created_at)
  then
    raise exception 'Contractor cannot modify protected fields';
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION public.tg_work_orders_block_contractor_edits() OWNER TO postgres;

--
-- Name: tg_work_orders_enforce_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_work_orders_enforce_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_old text := lower(coalesce(old.status, 'assigned'));
  v_new text := lower(coalesce(new.status, 'assigned'));
begin
  -- Only enforce when status is changing
  if v_new = v_old then
    return new;
  end if;

  -- Basic allowed set guard (extra safety)
  if v_new not in ('assigned','in_progress','completed','blocked','cancelled') then
    raise exception 'Invalid work order status: %', new.status
      using errcode = '23514'; -- check_violation
  end if;

  -- Transition rules
  if v_old = 'assigned' then
    if v_new not in ('in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old = 'in_progress' then
    if v_new not in ('completed','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old = 'blocked' then
    if v_new not in ('in_progress','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old in ('completed','cancelled') then
    -- Terminal states
    raise exception 'Cannot change status once %', old.status
      using errcode = '23514';

  else
    -- Unknown old status (legacy rows) — force user to move into a valid path
    -- Allow only into assigned/in_progress/blocked/cancelled (not straight to completed)
    if v_new not in ('assigned','in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.tg_work_orders_enforce_status_transition() OWNER TO postgres;

--
-- Name: tg_work_orders_guard_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.tg_work_orders_guard_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  old_s text := coalesce(old.status,'');
  new_s text := coalesce(new.status,'');
begin
  if new_s = old_s then
    return new;
  end if;

  if new_s not in ('assigned','in_progress','completed','blocked','cancelled') then
    raise exception 'Invalid work_orders.status: %', new_s;
  end if;

  if old_s = 'assigned' then
    if new_s not in ('in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s = 'in_progress' then
    if new_s not in ('completed','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s = 'blocked' then
    if new_s not in ('assigned','in_progress','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s in ('completed','cancelled') then
    raise exception 'Cannot change status after %', old_s;

  end if;

  return new;
end;
$$;


ALTER FUNCTION public.tg_work_orders_guard_status_transition() OWNER TO postgres;

--
-- Name: trg_work_orders_status_notify(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_work_orders_status_notify() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_members uuid[];
  v_contractor uuid;
  v_new_label text;
  v_old_label text;
begin
  -- Only fire when status actually changes
  if tg_op <> 'UPDATE' then
    return new;
  end if;

  if new.status is not distinct from old.status then
    return new;
  end if;

  v_account_id := new.account_id;
  if v_account_id is null then
    return new;
  end if;

  -- Polish labels (fallback handled in helper)
  select d.label into v_new_label
  from public.work_order_status_definitions d
  where lower(d.status) = lower(new.status)
  limit 1;

  select d.label into v_old_label
  from public.work_order_status_definitions d
  where lower(d.status) = lower(old.status)
  limit 1;

  -- Recipients: all account members
  select array_agg(am.user_id)
    into v_members
  from public.account_members am
  where am.account_id = v_account_id;

  if v_members is not null and array_length(v_members, 1) is not null then
    perform public.upsert_work_order_status_notifications(
      p_account_id        => v_account_id,
      p_recipient_user_ids=> v_members,
      p_work_order_id     => new.id,
      p_link_path         => '/work-orders/' || new.id::text,
      p_new_status        => new.status,
      p_old_status        => old.status,
      p_new_label         => v_new_label,
      p_old_label         => v_old_label,
      p_throttle_seconds  => 90
    );
  end if;

  -- Contractor recipient (separate link path)
  v_contractor := new.contractor_user_id;
  if v_contractor is not null then
    perform public.upsert_work_order_status_notifications(
      p_account_id        => v_account_id,
      p_recipient_user_ids=> array[v_contractor],
      p_work_order_id     => new.id,
      p_link_path         => '/contractor/jobs/' || new.id::text,
      p_new_status        => new.status,
      p_old_status        => old.status,
      p_new_label         => v_new_label,
      p_old_label         => v_old_label,
      p_throttle_seconds  => 90
    );
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.trg_work_orders_status_notify() OWNER TO postgres;

--
-- Name: update_payment(uuid, numeric, date, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_payment(p_payment_id uuid, p_amount numeric DEFAULT NULL::numeric, p_due_date date DEFAULT NULL::date, p_notes text DEFAULT NULL::text) RETURNS public.payments
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_row public.payments;
begin
  select * into v_row
  from public.payments
  where id = p_payment_id;

  if v_row.id is null then
    raise exception 'Payment not found';
  end if;

  if account_role_for(v_row.account_id) not in ('owner','admin','staff') then
    raise exception 'Not allowed';
  end if;

  update public.payments
  set
    amount   = coalesce(p_amount, amount),
    due_date = coalesce(p_due_date, due_date)
  where id = p_payment_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.update_payment(p_payment_id uuid, p_amount numeric, p_due_date date, p_notes text) OWNER TO postgres;

--
-- Name: update_payment_status_on_due(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_payment_status_on_due() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  IF NEW.status = 'Oczekujące'
     AND NEW.due_date < CURRENT_DATE THEN
    NEW.status := 'Zaległe';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_payment_status_on_due() OWNER TO postgres;

--
-- Name: upsert_security_anomaly_alert(uuid, text, text, text, text, uuid, text, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.upsert_security_anomaly_alert(p_account_id uuid, p_alert_type text, p_severity text, p_title text, p_summary text, p_actor_user_id uuid DEFAULT NULL::uuid, p_entity_type text DEFAULT NULL::text, p_entity_id uuid DEFAULT NULL::uuid, p_dedupe_key text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_alert_id uuid;
  v_alert_type text := lower(trim(coalesce(p_alert_type, '')));
  v_severity text := lower(trim(coalesce(p_severity, 'action')));
  v_dedupe_key text := trim(coalesce(p_dedupe_key, ''));
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if nullif(v_alert_type, '') is null then
    raise exception 'Missing alert type';
  end if;

  if nullif(trim(coalesce(p_title, '')), '') is null then
    raise exception 'Missing title';
  end if;

  if nullif(trim(coalesce(p_summary, '')), '') is null then
    raise exception 'Missing summary';
  end if;

  if v_severity not in ('info', 'action', 'urgent') then
    v_severity := 'action';
  end if;

  if v_dedupe_key = '' then
    v_dedupe_key := v_alert_type || ':' || coalesce(p_actor_user_id::text, 'account') || ':' || coalesce(p_entity_id::text, 'na');
  end if;

  update public.security_anomaly_alerts saa
  set
    severity = v_severity,
    actor_user_id = coalesce(p_actor_user_id, saa.actor_user_id),
    entity_type = coalesce(p_entity_type, saa.entity_type),
    entity_id = coalesce(p_entity_id, saa.entity_id),
    title = p_title,
    summary = p_summary,
    metadata = coalesce(p_metadata, '{}'::jsonb),
    alert_count = saa.alert_count + 1,
    last_seen_at = now(),
    resolved_at = null,
    resolved_by_user_id = null,
    resolution_note = null,
    status = case
      when lower(saa.status) = 'resolved' then 'open'
      else saa.status
    end
  where saa.account_id = p_account_id
    and saa.dedupe_key = v_dedupe_key
    and lower(saa.status) in ('open', 'acknowledged')
  returning saa.id into v_alert_id;

  if v_alert_id is not null then
    return v_alert_id;
  end if;

  insert into public.security_anomaly_alerts (
    account_id,
    alert_type,
    severity,
    status,
    actor_user_id,
    entity_type,
    entity_id,
    title,
    summary,
    metadata,
    dedupe_key
  )
  values (
    p_account_id,
    v_alert_type,
    v_severity,
    'open',
    p_actor_user_id,
    p_entity_type,
    p_entity_id,
    p_title,
    p_summary,
    coalesce(p_metadata, '{}'::jsonb),
    v_dedupe_key
  )
  returning id into v_alert_id;

  return v_alert_id;
end;
$$;


ALTER FUNCTION public.upsert_security_anomaly_alert(p_account_id uuid, p_alert_type text, p_severity text, p_title text, p_summary text, p_actor_user_id uuid, p_entity_type text, p_entity_id uuid, p_dedupe_key text, p_metadata jsonb) OWNER TO postgres;

--
-- Name: FUNCTION upsert_security_anomaly_alert(p_account_id uuid, p_alert_type text, p_severity text, p_title text, p_summary text, p_actor_user_id uuid, p_entity_type text, p_entity_id uuid, p_dedupe_key text, p_metadata jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.upsert_security_anomaly_alert(p_account_id uuid, p_alert_type text, p_severity text, p_title text, p_summary text, p_actor_user_id uuid, p_entity_type text, p_entity_id uuid, p_dedupe_key text, p_metadata jsonb) IS 'Creates or refreshes an active internal security anomaly alert using a dedupe key to avoid alert storms.';


--
-- Name: upsert_work_order_status_notifications(uuid, uuid[], uuid, text, text, text, text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.upsert_work_order_status_notifications(p_account_id uuid, p_recipient_user_ids uuid[], p_work_order_id uuid, p_link_path text, p_new_status text, p_old_status text, p_new_label text, p_old_label text, p_throttle_seconds integer DEFAULT 90) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_now timestamptz := now();
  v_rid uuid;
  v_existing_id uuid;
  v_to_insert uuid[] := '{}';
  v_title text := 'Zmieniono status zlecenia';
  v_body  text := 'Status: ' || coalesce(nullif(p_new_label,''), replace(coalesce(p_new_status,''), '_', ' ')) ||
                  case
                    when p_old_status is null then ''
                    else ' (poprzednio: ' || coalesce(nullif(p_old_label,''), replace(coalesce(p_old_status,''), '_', ' ')) || ')'
                  end;
  v_metadata jsonb := jsonb_build_object(
    'status', p_new_status,
    'old_status', p_old_status,
    'status_label', p_new_label,
    'old_status_label', p_old_label,
    'work_order_id', p_work_order_id
  );
begin
  if p_account_id is null or p_work_order_id is null then
    return;
  end if;

  if p_recipient_user_ids is null or array_length(p_recipient_user_ids, 1) is null then
    return;
  end if;

  foreach v_rid in array p_recipient_user_ids loop
    -- Find recent notification for this recipient + entity within throttle window
    select n.id
      into v_existing_id
    from public.notifications n
    where n.account_id = p_account_id
      and n.recipient_user_id = v_rid
      and n.type = 'work_order_status_changed'
      and n.entity_type = 'work_order'
      and n.entity_id = p_work_order_id
      and n.created_at >= (v_now - make_interval(secs => p_throttle_seconds))
    order by n.created_at desc
    limit 1;

    if v_existing_id is not null then
      -- Update instead of inserting a new one (throttle behavior)
      update public.notifications
         set title = v_title,
             body = v_body,
             link_path = p_link_path,
             metadata = coalesce(metadata, '{}'::jsonb) || v_metadata,
             -- keep read state as-is; if unread, it stays unread.
             updated_at = v_now
       where id = v_existing_id;
    else
      -- Queue for insert
      v_to_insert := v_to_insert || v_rid;
    end if;

    v_existing_id := null;
  end loop;

  -- Insert new notifications for any recipients that didn't have a recent one
  if array_length(v_to_insert, 1) is not null then
    perform public.create_notifications_system(
      p_account_id,
      v_to_insert,
      'work_order_status_changed',
      v_title,
      v_body,
      'work_order',
      p_work_order_id,
      p_link_path,
      v_metadata
    );
  end if;
end;
$$;


ALTER FUNCTION public.upsert_work_order_status_notifications(p_account_id uuid, p_recipient_user_ids uuid[], p_work_order_id uuid, p_link_path text, p_new_status text, p_old_status text, p_new_label text, p_old_label text, p_throttle_seconds integer) OWNER TO postgres;

--
-- Name: user_can_access_account(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.user_can_access_account(p_account_id uuid) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.account_members am
    where am.account_id = p_account_id
      and am.user_id = auth.uid()
  );
$$;


ALTER FUNCTION public.user_can_access_account(p_account_id uuid) OWNER TO postgres;

--
-- Name: FUNCTION user_can_access_account(p_account_id uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.user_can_access_account(p_account_id uuid) IS 'Authoritative helper for account membership checks in SECURITY DEFINER RPCs. Legacy owner_id-based RLS baselines should be treated as obsolete.';


--
-- Name: user_can_access_tenant(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.user_can_access_tenant(p_tenant_id uuid) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.tenants t
    where t.id = p_tenant_id
      and (
        t.user_id = auth.uid()
        or public.user_can_access_account(t.account_id)
      )
  );
$$;


ALTER FUNCTION public.user_can_access_tenant(p_tenant_id uuid) OWNER TO postgres;

--
-- Name: FUNCTION user_can_access_tenant(p_tenant_id uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.user_can_access_tenant(p_tenant_id uuid) IS 'Returns true if the current authenticated user is the tenant user or can access the tenant account as a manager/member.';


--
-- Name: user_can_manage_account(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.user_can_manage_account(p_account_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select (
    public.user_is_root_operator()
    or exists (
      select 1
      from public.account_members am
      where am.account_id = p_account_id
        and am.user_id = auth.uid()
        and lower(am.role::text) in ('owner', 'admin', 'staff')
    )
  );
$$;


ALTER FUNCTION public.user_can_manage_account(p_account_id uuid) OWNER TO postgres;

--
-- Name: user_is_root_operator(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.user_is_root_operator() RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.account_members am
    join public.accounts a on a.id = am.account_id
    where am.user_id = auth.uid()
      and coalesce(a.is_root, false) = true
  );
$$;


ALTER FUNCTION public.user_is_root_operator() OWNER TO postgres;

--
-- Name: void_payment(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.void_payment(p_payment_id uuid) RETURNS public.payments
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_pay public.payments;
  v_role text;
begin
  select * into v_pay
  from public.payments
  where id = p_payment_id;

  if not found then
    raise exception 'Payment not found';
  end if;

  v_role := public.account_role_for(v_pay.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  update public.payments
  set status = 'void',
      paid_at = null
  where id = p_payment_id
  returning * into v_pay;

  -- ledger row will be deleted by trigger
  return v_pay;
end;
$$;


ALTER FUNCTION public.void_payment(p_payment_id uuid) OWNER TO postgres;

--
-- Name: withdraw_application(uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.withdraw_application(p_application_id uuid, p_cancel_linked_draft_lease boolean DEFAULT true) RETURNS public.rental_applications
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_app record;
  v_lease record;
  v_out public.rental_applications;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  select a.* into v_app
  from public.rental_applications a
  where a.id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_app.status in ('withdrawn','rejected') then
    select * into v_out from public.rental_applications where id = p_application_id;
    return v_out;
  end if;

  if v_app.status = 'approved' then
    raise exception 'Cannot withdraw an approved application';
  end if;

  if exists (
    select 1
    from public.leases l
    where (l.application_id = v_app.id or l.property_id = v_app.property_id)
      and l.status = 'active'
  ) then
    raise exception 'Cannot withdraw: an active lease exists for this property/application';
  end if;

  if p_cancel_linked_draft_lease then
    select * into v_lease
    from public.leases l
    where l.application_id = v_app.id
    limit 1;

    if found and v_lease.status = 'draft' then
      update public.leases
      set status = 'cancelled',
          updated_at = now()
      where id = v_lease.id;

      update public.tenants
      set property_id = null
      where id = v_app.tenant_id
        and property_id = v_app.property_id;
    end if;
  end if;

  update public.rental_applications
  set status = 'withdrawn',
      updated_at = now()
  where id = v_app.id
  returning * into v_out;

  return v_out;
end;
$$;


ALTER FUNCTION public.withdraw_application(p_application_id uuid, p_cancel_linked_draft_lease boolean) OWNER TO postgres;

--
-- Name: work_order_financials; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.work_order_financials (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    work_order_id uuid NOT NULL,
    quote_amount numeric(12,2),
    quote_currency text DEFAULT 'PLN'::text,
    quote_notes text,
    quote_submitted_at timestamp with time zone,
    quote_submitted_by uuid,
    quote_status text DEFAULT 'draft'::text NOT NULL,
    invoice_amount numeric(12,2),
    invoice_currency text DEFAULT 'PLN'::text,
    invoice_issued_at timestamp with time zone,
    invoice_due_at timestamp with time zone,
    approved_at timestamp with time zone,
    approved_by uuid,
    rejected_at timestamp with time zone,
    rejected_by uuid,
    rejection_reason text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT quote_status_check CHECK ((quote_status = ANY (ARRAY['draft'::text, 'submitted'::text, 'approved'::text, 'rejected'::text])))
);


ALTER TABLE public.work_order_financials OWNER TO postgres;

--
-- Name: wo_fin_approve_quote(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.wo_fin_approve_quote(p_work_order_id uuid) RETURNS public.work_order_financials
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_row public.work_order_financials;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.is_account_manager(v_account_id, v_uid) then
    raise exception 'Not allowed (manager only)';
  end if;

  update public.work_order_financials
  set
    quote_status = 'approved',
    approved_at = now(),
    approved_by = v_uid,
    rejected_at = null,
    rejected_by = null,
    rejection_reason = null
  where work_order_id = p_work_order_id
    and quote_status = 'submitted'
  returning * into v_row;

  if v_row.id is null then
    raise exception 'Cannot approve quote (status must be submitted)';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION public.wo_fin_approve_quote(p_work_order_id uuid) OWNER TO postgres;

