--
-- Name: wo_fin_submit_quote(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.wo_fin_submit_quote(p_work_order_id uuid) RETURNS public.work_order_financials
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_row public.work_order_financials;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.is_assigned_contractor(p_work_order_id, v_uid) then
    raise exception 'Not allowed (contractor only)';
  end if;

  -- Must exist; if not, create empty draft first
  insert into public.work_order_financials(account_id, work_order_id, quote_status)
  values (v_account_id, p_work_order_id, 'draft')
  on conflict (work_order_id) do nothing;

  update public.work_order_financials
  set
    quote_status = 'submitted',
    quote_submitted_at = now(),
    quote_submitted_by = v_uid
  where work_order_id = p_work_order_id
    and quote_status in ('draft','rejected')
  returning * into v_row;

  if v_row.id is null then
    raise exception 'Cannot submit quote (status must be draft/rejected)';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION public.wo_fin_submit_quote(p_work_order_id uuid) OWNER TO postgres;

--
-- Name: wo_fin_upsert_invoice(uuid, numeric, text, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.wo_fin_upsert_invoice(p_work_order_id uuid, p_invoice_amount numeric, p_invoice_currency text, p_invoice_issued_at timestamp with time zone, p_invoice_due_at timestamp with time zone) RETURNS public.work_order_financials
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_row public.work_order_financials;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.is_assigned_contractor(p_work_order_id, v_uid) then
    raise exception 'Not allowed (contractor only)';
  end if;

  select * into v_row
  from public.work_order_financials f
  where f.work_order_id = p_work_order_id;

  if v_row.id is null then
    raise exception 'No financials row. Submit quote first.';
  end if;

  if v_row.quote_status <> 'approved' then
    raise exception 'Invoice allowed only after quote approved';
  end if;

  update public.work_order_financials
  set
    invoice_amount   = p_invoice_amount,
    invoice_currency = coalesce(nullif(p_invoice_currency,''),'PLN'),
    invoice_issued_at = p_invoice_issued_at,
    invoice_due_at    = p_invoice_due_at
  where work_order_id = p_work_order_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.wo_fin_upsert_invoice(p_work_order_id uuid, p_invoice_amount numeric, p_invoice_currency text, p_invoice_issued_at timestamp with time zone, p_invoice_due_at timestamp with time zone) OWNER TO postgres;

--
-- Name: wo_fin_upsert_quote_draft(uuid, numeric, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.wo_fin_upsert_quote_draft(p_work_order_id uuid, p_quote_amount numeric, p_quote_currency text, p_quote_notes text) RETURNS public.work_order_financials
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_existing public.work_order_financials;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.is_assigned_contractor(p_work_order_id, v_uid) then
    raise exception 'Not allowed (contractor only)';
  end if;

  select * into v_existing
  from public.work_order_financials f
  where f.work_order_id = p_work_order_id;

  -- Block editing if already approved
  if v_existing.id is not null and v_existing.quote_status in ('submitted','approved') then
    raise exception 'Quote already submitted/approved';
  end if;

  insert into public.work_order_financials (
    account_id, work_order_id,
    quote_amount, quote_currency, quote_notes,
    quote_status
  )
  values (
    v_account_id, p_work_order_id,
    p_quote_amount, coalesce(nullif(p_quote_currency,''),'PLN'), p_quote_notes,
    'draft'
  )
  on conflict (work_order_id) do update
  set
    quote_amount   = excluded.quote_amount,
    quote_currency = excluded.quote_currency,
    quote_notes    = excluded.quote_notes,
    quote_status   = 'draft'
  returning * into v_existing;

  return v_existing;
end;
$$;


ALTER FUNCTION public.wo_fin_upsert_quote_draft(p_work_order_id uuid, p_quote_amount numeric, p_quote_currency text, p_quote_notes text) OWNER TO postgres;

