-- Name: work_order_can_transition(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_can_transition(p_from text, p_to text) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1
    from public.work_order_status_transitions t
    where t.from_status = lower(coalesce(p_from, ''))
      and t.to_status   = lower(coalesce(p_to, ''))
  );
$$;


