--
-- Name: work_order_create(uuid, uuid, uuid, uuid, text, text, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_create(p_account_id uuid, p_property_id uuid, p_maintenance_request_id uuid DEFAULT NULL::uuid, p_contractor_id uuid DEFAULT NULL::uuid, p_contractor_name text DEFAULT NULL::text, p_contractor_phone text DEFAULT NULL::text, p_scheduled_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text) RETURNS public.work_orders
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_user_id uuid;
  v_contractor_user_id uuid;
  v_name text;
  v_phone text;
  v_row public.work_orders;
begin
  if p_account_id is null then raise exception 'Missing account_id'; end if;
  if p_property_id is null then raise exception 'Missing property_id'; end if;

  v_user_id := auth.uid();
  if v_user_id is null then
    raise exception 'Not authenticated';
  end if;

  -- If contractor selected from directory, resolve user_id + name/phone
  if p_contractor_id is not null then
    select c.user_id, c.name, c.phone
      into v_contractor_user_id, v_name, v_phone
    from public.contractors c
    where c.id = p_contractor_id
      and c.account_id = p_account_id
      and coalesce(c.active, true) = true;
  end if;

  insert into public.work_orders (
    account_id,
    property_id,
    maintenance_request_id,
    contractor_user_id,
    contractor_name,
    contractor_phone,
    status,
    scheduled_at,
    notes,
    created_by,
    created_at,
    updated_at
  )
  values (
    p_account_id,
    p_property_id,
    p_maintenance_request_id,
    v_contractor_user_id,
    coalesce(v_name, p_contractor_name),
    coalesce(v_phone, p_contractor_phone),
    'assigned',
    p_scheduled_at,
    p_notes,
    v_user_id,
    now(),
    now()
  )
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION public.work_order_create(p_account_id uuid, p_property_id uuid, p_maintenance_request_id uuid, p_contractor_id uuid, p_contractor_name text, p_contractor_phone text, p_scheduled_at timestamp with time zone, p_notes text) OWNER TO postgres;

--
-- Name: work_order_deny_tenant_cancellation(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_deny_tenant_cancellation(p_work_order_id uuid, p_reason text DEFAULT NULL::text) RETURNS public.work_orders
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_wo public.work_orders;
begin
  select * into v_wo
  from public.work_orders
  where id = p_work_order_id;

  if not found then
    raise exception 'Work order not found: %', p_work_order_id
      using errcode = 'P0002';
  end if;

  if not public.can_access_account(v_wo.account_id) then
    raise exception 'Only account members can deny cancellations'
      using errcode = '42501';
  end if;

  if not public.work_order_has_pending_cancel_request(p_work_order_id) then
    raise exception 'No pending tenant cancellation request'
      using errcode = 'P0001';
  end if;

  insert into public.work_order_audit_log (
    work_order_id, account_id, actor_user_id, action, old_value, new_value
  )
  values (
    v_wo.id, v_wo.account_id, auth.uid(), 'tenant_cancellation_denied',
    jsonb_build_object('status', v_wo.status),
    jsonb_build_object('reason', p_reason)
  );

  return v_wo;
end;
$$;


ALTER FUNCTION public.work_order_deny_tenant_cancellation(p_work_order_id uuid, p_reason text) OWNER TO postgres;

--
-- Name: work_order_has_pending_cancel_request(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_has_pending_cancel_request(p_work_order_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  with last_request as (
    select max(created_at) as at
    from public.work_order_audit_log
    where work_order_id = p_work_order_id
      and action = 'tenant_cancellation_requested'
  ),
  last_resolution as (
    select max(created_at) as at
    from public.work_order_audit_log
    where work_order_id = p_work_order_id
      and action in ('tenant_cancellation_approved','tenant_cancellation_denied')
  )
  select
    (select at from last_request) is not null
    and coalesce((select at from last_request), '-infinity'::timestamptz)
        > coalesce((select at from last_resolution), '-infinity'::timestamptz);
$$;


ALTER FUNCTION public.work_order_has_pending_cancel_request(p_work_order_id uuid) OWNER TO postgres;

--
-- Name: work_order_notify_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_notify_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_recipients uuid[];
  v_title text;
  v_body text;
  v_label text;
  v_window_seconds integer;
  v_uid uuid;
begin
  -- Only act when status actually changes
  if new.status is null
     or old.status is null
     or new.status = old.status then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  -- Polish label
  select d.label
    into v_label
  from public.work_order_status_definitions d
  where d.status = new.status;

  if v_label is null then
    v_label := replace(new.status, '_', ' ');
  end if;

  v_title := 'Status zlecenia zmieniony';
  v_body  := 'Nowy status: ' || v_label;

  -- Throttle window (seconds)
  -- Terminal statuses should always notify (0 = no throttling)
  v_window_seconds :=
    case new.status
      when 'completed' then 0
      when 'cancelled' then 0
      when 'blocked'   then 0
      else 90
    end;

  /* -----------------------------
     Notify account members (owner/staff/admin)
  ----------------------------- */
  select array_agg(am.user_id)
    into v_recipients
  from public.account_members am
  where am.account_id = new.account_id;

  if v_recipients is not null and array_length(v_recipients, 1) > 0 then
    foreach v_uid in array v_recipients loop
      if v_window_seconds = 0
         or public.should_send_notification(
              new.account_id,
              v_uid,
              'work_order_status_changed',
              'work_order',
              new.id,
              v_window_seconds
            )
      then
        perform public.create_notifications_system(
          new.account_id,
          array[v_uid],
          'work_order_status_changed',
          v_title,
          v_body,
          'work_order',
          new.id,
          '/work-orders/' || new.id::text,
          jsonb_build_object(
            'property_id', new.property_id,
            'from_status', old.status,
            'to_status', new.status,
            'status_label', v_label
          )
        );
      end if;
    end loop;
  end if;

  /* -----------------------------
     Notify contractor (if assigned)
  ----------------------------- */
  if new.contractor_user_id is not null then
    if v_window_seconds = 0
       or public.should_send_notification(
            new.account_id,
            new.contractor_user_id,
            'work_order_status_changed',
            'work_order',
            new.id,
            v_window_seconds
          )
    then
      perform public.create_notifications_system(
        new.account_id,
        array[new.contractor_user_id],
        'work_order_status_changed',
        v_title,
        v_body,
        'work_order',
        new.id,
        '/contractor/jobs/' || new.id::text,
        jsonb_build_object(
          'property_id', new.property_id,
          'from_status', old.status,
          'to_status', new.status,
          'status_label', v_label
        )
      );
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.work_order_notify_status_change() OWNER TO postgres;

--
-- Name: work_order_set_status(uuid, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_order_set_status(p_work_order_id uuid, p_new_status text, p_apply_if_tenant_allowed boolean DEFAULT false) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_old_status text;
  v_account_id uuid;
  v_is_member boolean;
  v_is_tenant boolean;
  v_next text := lower(coalesce(p_new_status,''));
begin
  select wo.status, wo.account_id
    into v_old_status, v_account_id
  from public.work_orders wo
  where wo.id = p_work_order_id;

  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  v_old_status := lower(coalesce(v_old_status, 'assigned'));

  -- Membership check (owner/admin/staff)
  v_is_member := public.is_account_member(v_account_id);

  -- Tenant check (property-based)
  v_is_tenant := exists (
    select 1
    from public.work_orders wo
    join public.tenants t
      on t.user_id = auth.uid()
    where wo.id = p_work_order_id
      and t.archived_at is null
      and t.status = any(array['active','accepted_pending_signing'])
      and t.property_id is not null
      and t.property_id = wo.property_id
  );

  -- =========================================================
  -- TENANT: cancellation request is an AUDIT event only
  -- (no status change; owner/staff approves/denies later)
  -- =========================================================
  if (v_is_tenant and v_next = 'cancelled') then
    insert into public.work_order_audit_log (
      work_order_id,
      actor_user_id,
      action,
      old_value,
      new_value,
      account_id
    )
    values (
      p_work_order_id,
      auth.uid(),
      'tenant_cancellation_requested',
      jsonb_build_object('status', v_old_status),
      jsonb_build_object('requested_status', 'cancelled'),
      v_account_id
    );

    return;
  end if;

  -- =========================================================
  -- MEMBERS: real status changes must be valid via transitions table
  -- =========================================================
  if not v_is_member then
    raise exception 'Not authorized to change/request status for this work order';
  end if;

  if not public.work_order_can_transition(v_old_status, v_next) then
    raise exception 'Invalid status transition: % -> %', v_old_status, v_next;
  end if;

  update public.work_orders
  set status = v_next,
      updated_at = now()
  where id = p_work_order_id;

  insert into public.work_order_audit_log (
    work_order_id,
    actor_user_id,
    action,
    old_value,
    new_value,
    account_id
  )
  values (
    p_work_order_id,
    auth.uid(),
    'status_changed',
    jsonb_build_object('status', v_old_status),
    jsonb_build_object('status', v_next),
    v_account_id
  );
end;
$$;


ALTER FUNCTION public.work_order_set_status(p_work_order_id uuid, p_new_status text, p_apply_if_tenant_allowed boolean) OWNER TO postgres;

--
-- Name: work_orders_notify_trg_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.work_orders_notify_trg_fn() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_members uuid[];
  v_contractor uuid;
  v_label text;
  v_title text;
  v_body text;
  v_window int := 60; -- seconds: adjust if you want more/less throttle
  v_uid uuid;
begin
  -- Safety guards
  if new.account_id is null then
    return new;
  end if;

  -- Load account member recipients (owners/staff/admin live here)
  select array_agg(am.user_id)
    into v_members
  from public.account_members am
  where am.account_id = new.account_id;

  v_contractor := new.contractor_user_id;

  -- ---------- INSERT: created ----------
  if tg_op = 'INSERT' then
    if v_members is not null and array_length(v_members, 1) is not null then
      foreach v_uid in array v_members loop
        if not public.should_throttle_notification(
          new.account_id, v_uid,
          'work_order_created',
          'work_order', new.id,
          v_window
        ) then
          perform public.create_notifications_system(
            new.account_id,
            array[v_uid],
            'work_order_created',
            'Nowe zlecenie utworzone',
            'Utworzono nowe zlecenie serwisowe.',
            'work_order',
            new.id,
            '/work-orders/' || new.id::text,
            jsonb_build_object(
              'work_order_id', new.id,
              'property_id', new.property_id,
              'maintenance_request_id', new.maintenance_request_id,
              'status', new.status
            )
          );
        end if;
      end loop;
    end if;

    -- If contractor already assigned at creation, notify contractor too
    if v_contractor is not null then
      if not public.should_throttle_notification(
        new.account_id, v_contractor,
        'work_order_assigned',
        'work_order', new.id,
        v_window
      ) then
        perform public.create_notifications_system(
          new.account_id,
          array[v_contractor],
          'work_order_assigned',
          'Masz nowe zlecenie',
          'Przypisano do Ciebie nowe zlecenie.',
          'work_order',
          new.id,
          '/contractor/jobs/' || new.id::text,
          jsonb_build_object(
            'work_order_id', new.id,
            'property_id', new.property_id,
            'status', new.status
          )
        );
      end if;
    end if;

    return new;
  end if;

  -- ---------- UPDATE: contractor assignment changed ----------
  if tg_op = 'UPDATE' then
    -- Notify contractor if contractor_user_id changed to a real value
    if new.contractor_user_id is distinct from old.contractor_user_id
       and new.contractor_user_id is not null then
      if not public.should_throttle_notification(
        new.account_id, new.contractor_user_id,
        'work_order_assigned',
        'work_order', new.id,
        v_window
      ) then
        perform public.create_notifications_system(
          new.account_id,
          array[new.contractor_user_id],
          'work_order_assigned',
          'Masz nowe zlecenie',
          'Przypisano do Ciebie zlecenie.',
          'work_order',
          new.id,
          '/contractor/jobs/' || new.id::text,
          jsonb_build_object(
            'work_order_id', new.id,
            'property_id', new.property_id,
            'status', new.status
          )
        );
      end if;
    end if;

    -- ---------- UPDATE: status changed ----------
    if new.status is distinct from old.status then
      -- Polish label from definitions
      select d.label
        into v_label
      from public.work_order_status_definitions d
      where d.status = new.status
      limit 1;

      v_label := coalesce(nullif(v_label, ''), new.status);

      v_title := 'Zmieniono status zlecenia';
      v_body  := 'Nowy status: ' || v_label;

      -- Notify account members
      if v_members is not null and array_length(v_members, 1) is not null then
        foreach v_uid in array v_members loop
          if not public.should_throttle_notification(
            new.account_id, v_uid,
            'work_order_status_changed',
            'work_order', new.id,
            v_window
          ) then
            perform public.create_notifications_system(
              new.account_id,
              array[v_uid],
              'work_order_status_changed',
              v_title,
              v_body,
              'work_order',
              new.id,
              '/work-orders/' || new.id::text,
              jsonb_build_object(
                'work_order_id', new.id,
                'property_id', new.property_id,
                'old_status', old.status,
                'new_status', new.status,
                'new_status_label', v_label
              )
            );
          end if;
        end loop;
      end if;

      -- Optional: notify contractor too if assigned
      if new.contractor_user_id is not null then
        if not public.should_throttle_notification(
          new.account_id, new.contractor_user_id,
          'work_order_status_changed',
          'work_order', new.id,
          v_window
        ) then
          perform public.create_notifications_system(
            new.account_id,
            array[new.contractor_user_id],
            'work_order_status_changed',
            v_title,
            v_body,
            'work_order',
            new.id,
            '/contractor/jobs/' || new.id::text,
            jsonb_build_object(
              'work_order_id', new.id,
              'property_id', new.property_id,
              'old_status', old.status,
              'new_status', new.status,
              'new_status_label', v_label
            )
          );
        end if;
      end if;
    end if;

    return new;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.work_orders_notify_trg_fn() OWNER TO postgres;

--
-- Name: your_function_name_here(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.your_function_name_here() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_request_id uuid;
  v_total int;
  v_not_completed int;
begin
  v_request_id := coalesce(new.maintenance_request_id, old.maintenance_request_id);

  if v_request_id is null then
    return coalesce(new, old);
  end if;

  -- Count work orders for this maintenance request
  select count(*) into v_total
  from public.work_orders wo
  where wo.maintenance_request_id = v_request_id;

  -- Count work orders that are NOT completed
  select count(*) into v_not_completed
  from public.work_orders wo
  where wo.maintenance_request_id = v_request_id
    and coalesce(wo.status,'') <> 'completed';

  /*
    RULES:
    - If request is CLOSED, never auto-change it.
    - If there is at least 1 WO and not all completed => in_progress (unless already resolved/closed).
    - If there is at least 1 WO and all completed => resolved (unless closed).
  */

  -- 1) All completed => resolved
  if v_total > 0 and v_not_completed = 0 then
    update public.maintenance_requests mr
    set status = 'resolved',
        updated_at = now()
    where mr.id = v_request_id
      and mr.status <> 'closed';  -- don't override manual closure

    return coalesce(new, old);
  end if;

  -- 2) Some not completed => in_progress (but don't reopen resolved/closed)
  if v_total > 0 and v_not_completed > 0 then
    update public.maintenance_requests mr
    set status = 'in_progress',
        updated_at = now()
    where mr.id = v_request_id
      and mr.status in ('open', 'waiting', 'in_progress'); -- don't downgrade resolved/closed

    return coalesce(new, old);
  end if;

  -- 3) No work orders => do nothing (keep whatever it currently is)
  return coalesce(new, old);
end;
$$;


ALTER FUNCTION public.your_function_name_here() OWNER TO postgres;

