  WHERE ((wo.id = work_order_attachments.work_order_id) AND (wo.account_id = work_order_attachments.account_id) AND ((EXISTS ( SELECT 1
           FROM public.account_members am
          WHERE ((am.account_id = wo.account_id) AND (am.user_id = auth.uid()) AND (lower((am.role)::text) = ANY (ARRAY['owner'::text, 'admin'::text, 'staff'::text]))))) OR (wo.contractor_user_id = auth.uid())))))));


